const _sections = {"1":"","2":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\"><span class=\"nt lhs\">BlockStatement</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">Block</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n\n<span class=\"nt lhs\">Block</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">{</span> <span class=\"nt\">StatementList</span><span class=\"p\">[?Yield, ?Await, ?Return]</span><span class=\"mod\">?</span> <span class=\"t\">}</span>\n\n<span class=\"nt lhs\">StatementList</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">StatementListItem</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"nt\">StatementList</span><span class=\"p\">[?Yield, ?Await, ?Return]</span> <span class=\"nt\">StatementListItem</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n\n<span class=\"nt lhs\">StatementListItem</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"nt\">Declaration</span><span class=\"p\">[?Yield, ?Await]</span></pre>\n\n    ","3":"","4":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\"><span class=\"nt lhs\">EmptyStatement</span> <span class=\"geq\">:</span>\n  <span class=\"t\">;</span></pre>\n\n    ","5":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\"><span class=\"nt lhs\">ExpressionStatement</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"p\">[lookahead &notin; { `{`, `function`, `async` [no LineTerminator here]</span> <span class=\"t\">function</span>, <span class=\"t\">class</span>, <span class=\"t\">let</span> <span class=\"t\">[</span> }] <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">;</span></pre>\n    <emu-note>\n      <p>An <emu-nt>ExpressionStatement</emu-nt> cannot start with a U+007B (LEFT CURLY BRACKET) because that might make it ambiguous with a <emu-nt>Block</emu-nt>. An <emu-nt>ExpressionStatement</emu-nt> cannot start with the <code>function</code> or <code>class</code> keywords because that would make it ambiguous with a <emu-nt>FunctionDeclaration</emu-nt>, a <emu-nt>GeneratorDeclaration</emu-nt>, or a <emu-nt>ClassDeclaration</emu-nt>. An <emu-nt>ExpressionStatement</emu-nt> cannot start with <code>async function</code> because that would make it ambiguous with an <emu-nt>AsyncFunctionDeclaration</emu-nt> or a <emu-nt>AsyncGeneratorDeclaration</emu-nt>. An <emu-nt>ExpressionStatement</emu-nt> cannot start with the two token sequence <code>let [</code> because that would make it ambiguous with a <code>let</code> <emu-nt>LexicalDeclaration</emu-nt> whose first <emu-nt>LexicalBinding</emu-nt> was an <emu-nt>ArrayBindingPattern</emu-nt>.</p>\n    </emu-note>\n\n    ","6":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\"><span class=\"nt lhs\">IfStatement</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">if</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span> <span class=\"t\">else</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"t\">if</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span> <span class=\"p\">[lookahead != `else`]</span></pre>\n    <emu-note>The lookahead-restriction [lookahead ≠ <code>else</code>] resolves the classic \"dangling else\" problem in the usual way. That is, when the choice of associated <code>if</code> is otherwise ambiguous, the <code>else</code> is associated with the nearest (innermost) of the candidate <code>if</code>s</emu-note>\n\n    ","7":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\"><span class=\"nt lhs\">IterationStatement</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">DoWhileStatement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"nt\">WhileStatement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"nt\">ForStatement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"nt\">ForInOfStatement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span></pre>\n\n    ","8":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\"><span class=\"nt lhs\">ContinueStatement</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">continue</span> <span class=\"t\">;</span>\n  <span class=\"t\">continue</span> <span class=\"p\">[no LineTerminator here]</span> <span class=\"nt\">LabelIdentifier</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">;</span></pre>\n\n    ","9":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\"><span class=\"nt lhs\">BreakStatement</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">break</span> <span class=\"t\">;</span>\n  <span class=\"t\">break</span> <span class=\"p\">[no LineTerminator here]</span> <span class=\"nt\">LabelIdentifier</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">;</span></pre>\n\n    ","10":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\"><span class=\"nt lhs\">ReturnStatement</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">return</span> <span class=\"t\">;</span>\n  <span class=\"t\">return</span> <span class=\"p\">[no LineTerminator here]</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">;</span></pre>\n    <emu-note>\n      <p>A <code>return</code> statement causes a function to cease execution and, in most cases, returns a value to the caller. If <emu-nt>Expression</emu-nt> is omitted, the return value is <b>undefined</b>. Otherwise, the return value is the value of <emu-nt>Expression</emu-nt>. A <code>return</code> statement may not actually return a value to the caller depending on surrounding context. For example, in a <code>try</code> block, a <code>return</code> statement's Completion Record may be replaced with another Completion Record during evaluation of the <code>finally</code> block.</p>\n    </emu-note>\n\n    ","11":"<emu-note>\n      <p>Use of the Legacy <code>with</code> statement is discouraged in new ECMAScript code. Consider alternatives that are permitted in both strict mode code and non-strict code, such as <a href=\"/ecmascript-language-expressions#sec-destructuring-assignment\">destructuring assignment</a>.</p>\n    </emu-note>\n\n    <h2>Syntax</h2>\n    <pre class=\"emu-grammar\"><span class=\"nt lhs\">WithStatement</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">with</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span></pre>\n    <emu-note>\n      <p>The <code>with</code> statement adds an Object Environment Record for a computed object to the lexical environment of the running execution context. It then executes a statement using this augmented lexical environment. Finally, it restores the original lexical environment.</p>\n    </emu-note>\n\n    ","12":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\"><span class=\"nt lhs\">SwitchStatement</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">switch</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"nt\">CaseBlock</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n\n<span class=\"nt lhs\">CaseBlock</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">{</span> <span class=\"nt\">CaseClauses</span><span class=\"p\">[?Yield, ?Await, ?Return]</span><span class=\"mod\">?</span> <span class=\"t\">}</span>\n  <span class=\"t\">{</span> <span class=\"nt\">CaseClauses</span><span class=\"p\">[?Yield, ?Await, ?Return]</span><span class=\"mod\">?</span> <span class=\"nt\">DefaultClause</span><span class=\"p\">[?Yield, ?Await, ?Return]</span> <span class=\"nt\">CaseClauses</span><span class=\"p\">[?Yield, ?Await, ?Return]</span><span class=\"mod\">?</span> <span class=\"t\">}</span>\n\n<span class=\"nt lhs\">CaseClauses</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">CaseClause</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"nt\">CaseClauses</span><span class=\"p\">[?Yield, ?Await, ?Return]</span> <span class=\"nt\">CaseClause</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n\n<span class=\"nt lhs\">CaseClause</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">case</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">:</span> <span class=\"nt\">StatementList</span><span class=\"p\">[?Yield, ?Await, ?Return]</span><span class=\"mod\">?</span>\n\n<span class=\"nt lhs\">DefaultClause</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">default</span> <span class=\"t\">:</span> <span class=\"nt\">StatementList</span><span class=\"p\">[?Yield, ?Await, ?Return]</span><span class=\"mod\">?</span></pre>\n\n    ","13":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\"><span class=\"nt lhs\">LabelledStatement</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">LabelIdentifier</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">:</span> <span class=\"nt\">LabelledItem</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n\n<span class=\"nt lhs\">LabelledItem</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"nt\">FunctionDeclaration</span><span class=\"p\">[?Yield, ?Await, ~Default]</span></pre>\n    <emu-note>\n      <p>A <emu-nt>Statement</emu-nt> may be prefixed by a label. Labelled statements are only used in conjunction with labelled <code>break</code> and <code>continue</code> statements. ECMAScript has no <code>goto</code> statement. A <emu-nt>Statement</emu-nt> can be part of a <emu-nt>LabelledStatement</emu-nt>, which itself can be part of a <emu-nt>LabelledStatement</emu-nt>, and so on. The labels introduced this way are collectively referred to as the “current label set” when describing the semantics of individual statements.</p>\n    </emu-note>\n\n    ","14":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\"><span class=\"nt lhs\">ThrowStatement</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">throw</span> <span class=\"p\">[no LineTerminator here]</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">;</span></pre>\n\n    ","15":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\"><span class=\"nt lhs\">TryStatement</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">try</span> <span class=\"nt\">Block</span><span class=\"p\">[?Yield, ?Await, ?Return]</span> <span class=\"nt\">Catch</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"t\">try</span> <span class=\"nt\">Block</span><span class=\"p\">[?Yield, ?Await, ?Return]</span> <span class=\"nt\">Finally</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"t\">try</span> <span class=\"nt\">Block</span><span class=\"p\">[?Yield, ?Await, ?Return]</span> <span class=\"nt\">Catch</span><span class=\"p\">[?Yield, ?Await, ?Return]</span> <span class=\"nt\">Finally</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n\n<span class=\"nt lhs\">Catch</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">catch</span> <span class=\"t\">(</span> <span class=\"nt\">CatchParameter</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"nt\">Block</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"t\">catch</span> <span class=\"nt\">Block</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n\n<span class=\"nt lhs\">Finally</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">finally</span> <span class=\"nt\">Block</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n\n<span class=\"nt lhs\">CatchParameter</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">BindingIdentifier</span><span class=\"p\">[?Yield, ?Await]</span>\n  <span class=\"nt\">BindingPattern</span><span class=\"p\">[?Yield, ?Await]</span></pre>\n    <emu-note>\n      <p>The <code>try</code> statement encloses a block of code in which an exceptional condition can occur, such as a runtime error or a <code>throw</code> statement. The <code>catch</code> clause provides the exception-handling code. When a catch clause catches an exception, its <emu-nt>CatchParameter</emu-nt> is bound to that exception.</p>\n    </emu-note>\n\n    ","16":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\"><span class=\"nt lhs\">DebuggerStatement</span> <span class=\"geq\">:</span>\n  <span class=\"t\">debugger</span> <span class=\"t\">;</span></pre>\n\n    ","":"<h2>Syntax</h2>\n  <pre class=\"emu-grammar\"><span class=\"nt lhs\">Statement</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">BlockStatement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"nt\">VariableStatement</span><span class=\"p\">[?Yield, ?Await]</span>\n  <span class=\"nt\">EmptyStatement</span>\n  <span class=\"nt\">ExpressionStatement</span><span class=\"p\">[?Yield, ?Await]</span>\n  <span class=\"nt\">IfStatement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"nt\">BreakableStatement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"nt\">ContinueStatement</span><span class=\"p\">[?Yield, ?Await]</span>\n  <span class=\"nt\">BreakStatement</span><span class=\"p\">[?Yield, ?Await]</span>\n  <span class=\"p\">[+Return]</span> <span class=\"nt\">ReturnStatement</span><span class=\"p\">[?Yield, ?Await]</span>\n  <span class=\"nt\">WithStatement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"nt\">LabelledStatement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"nt\">ThrowStatement</span><span class=\"p\">[?Yield, ?Await]</span>\n  <span class=\"nt\">TryStatement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"nt\">DebuggerStatement</span>\n\n<span class=\"nt lhs\">Declaration</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">HoistableDeclaration</span><span class=\"p\">[?Yield, ?Await, ~Default]</span>\n  <span class=\"nt\">ClassDeclaration</span><span class=\"p\">[?Yield, ?Await, ~Default]</span>\n  <span class=\"nt\">LexicalDeclaration</span><span class=\"p\">[+In, ?Yield, ?Await]</span>\n\n<span class=\"nt lhs\">HoistableDeclaration</span><span class=\"p\">[Yield, Await, Default]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">FunctionDeclaration</span><span class=\"p\">[?Yield, ?Await, ?Default]</span>\n  <span class=\"nt\">GeneratorDeclaration</span><span class=\"p\">[?Yield, ?Await, ?Default]</span>\n  <span class=\"nt\">AsyncFunctionDeclaration</span><span class=\"p\">[?Yield, ?Await, ?Default]</span>\n  <span class=\"nt\">AsyncGeneratorDeclaration</span><span class=\"p\">[?Yield, ?Await, ?Default]</span>\n\n<span class=\"nt lhs\">BreakableStatement</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">IterationStatement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"nt\">SwitchStatement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span></pre>\n\n  ","1.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">HoistableDeclaration</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">GeneratorDeclaration</span>\n  <span class=\"nt\">AsyncFunctionDeclaration</span>\n  <span class=\"nt\">AsyncGeneratorDeclaration</span></pre>\n      <emu-alg><ol><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">HoistableDeclaration</span> <span class=\"geq\">:</span> <span class=\"nt\">FunctionDeclaration</span></pre>\n      <emu-alg><ol><li>Return ? Evaluation of <emu-nt>FunctionDeclaration</emu-nt>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">BreakableStatement</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">IterationStatement</span>\n  <span class=\"nt\">SwitchStatement</span></pre>\n      <emu-alg><ol><li>Let <var>newLabelSet</var> be a new empty List.</li><li>Return ? LabelledEvaluation of this <emu-nt>BreakableStatement</emu-nt> with argument <var>newLabelSet</var>.</li></ol></emu-alg>\n    ","2.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">Block</span> <span class=\"geq\">:</span> <span class=\"t\">{</span> <span class=\"nt\">StatementList</span> <span class=\"t\">}</span></pre>\n      <ul>\n        <li>\n          <p>It is a Syntax Error if the LexicallyDeclaredNames of <emu-nt>StatementList</emu-nt> contains any duplicate entries<span normative-optional>, unless the host is a web browser or otherwise supports <a href=\"/additional-ecmascript-features-for-web-browsers#sec-block-level-function-declarations-web-legacy-compatibility-semantics\">B.3.2</a>, and both of the following conditions are true:</span></p>\n          <ul normative-optional>\n            <li>IsStrict(this production) is <b>false</b>.</li>\n            <li>The duplicate entries are only bound by FunctionDeclarations.</li>\n          </ul>\n        </li>\n        <li>\n          It is a Syntax Error if any element of the LexicallyDeclaredNames of <emu-nt>StatementList</emu-nt> also occurs in the VarDeclaredNames of <emu-nt>StatementList</emu-nt>.\n        </li>\n      </ul>\n    ","2.2":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">Block</span> <span class=\"geq\">:</span> <span class=\"t\">{</span> <span class=\"t\">}</span></pre>\n      <emu-alg><ol><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">Block</span> <span class=\"geq\">:</span> <span class=\"t\">{</span> <span class=\"nt\">StatementList</span> <span class=\"t\">}</span></pre>\n      <emu-alg><ol><li>Let <var>oldEnv</var> be the running execution context's LexicalEnvironment.</li><li>Let <var>blockEnv</var> be NewDeclarativeEnvironment(<var>oldEnv</var>).</li><li>Perform BlockDeclarationInstantiation(<emu-nt>StatementList</emu-nt>, <var>blockEnv</var>).</li><li>Set the running execution context's LexicalEnvironment to <var>blockEnv</var>.</li><li>Let <var>blockValue</var> be Completion(Evaluation of <emu-nt>StatementList</emu-nt>).</li><li>Set the running execution context's LexicalEnvironment to <var>oldEnv</var>.</li><li>Return ? <var>blockValue</var>.</li></ol></emu-alg>\n      <emu-note>\n        <p>No matter how control leaves the <emu-nt>Block</emu-nt> the LexicalEnvironment is always restored to its former state.</p>\n      </emu-note>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">StatementList</span> <span class=\"geq\">:</span> <span class=\"nt\">StatementList</span> <span class=\"nt\">StatementListItem</span></pre>\n      <emu-alg><ol><li>Let <var>sl</var> be ? Evaluation of <emu-nt>StatementList</emu-nt>.</li><li>Let <var>s</var> be Completion(Evaluation of <emu-nt>StatementListItem</emu-nt>).</li><li>Return ? UpdateEmpty(<var>s</var>, <var>sl</var>).</li></ol></emu-alg>\n      <emu-note>\n        <p>The value of a <emu-nt>StatementList</emu-nt> is the value of the last value-producing item in the <emu-nt>StatementList</emu-nt>. For example, the following calls to the <code>eval</code> function all return the value 1:</p>\n        <pre><code class=\"javascript\">\n          eval(\"1;;;;;\")\n          eval(\"1;{}\")\n          eval(\"1;var a;\")\n        </code></pre>\n      </emu-note>\n    ","2.3":"<dl class=\"header\">\n        <dt>description</dt>\n        <dd><var>code</var> is the Parse Node corresponding to the body of the block. <var>env</var> is the Environment Record in which bindings are to be created.</dd>\n      </dl>\n      <emu-note>\n        <p>When a <emu-nt>Block</emu-nt> or <emu-nt>CaseBlock</emu-nt> is evaluated a new Declarative Environment Record is created and bindings for each block scoped variable, constant, function, or class declared in the block are instantiated in the Environment Record.</p>\n      </emu-note>\n      <p>It performs the following steps when called:</p>\n      <emu-alg><ol><li>Let <var>declarations</var> be the LexicallyScopedDeclarations of <var>code</var>.</li><li>Let <var>privateEnv</var> be the running execution context's PrivateEnvironment.</li><li>For each element <var>decl</var> of <var>declarations</var>, do<ol><li>For each element <var>dn</var> of the BoundNames of <var>decl</var>, do<ol><li>If IsConstantDeclaration of <var>decl</var> is <b>true</b>, then<ol><li>Perform ! <var>env</var>.CreateImmutableBinding(<var>dn</var>, <b>true</b>).</li></ol></li><li>Else,<ol><li>If the host is a web browser or otherwise supports <a href=\"/additional-ecmascript-features-for-web-browsers#sec-block-level-function-declarations-web-legacy-compatibility-semantics\">B.3.2</a>, then<ol><li>If ! <var>env</var>.HasBinding(<var>dn</var>) is <b>false</b>, then<ol><li>Perform ! <var>env</var>.CreateMutableBinding(<var>dn</var>, <b>false</b>).</li></ol></li></ol></li><li>Else,<ol><li>Perform ! <var>env</var>.CreateMutableBinding(<var>dn</var>, <b>false</b>).</li></ol></li></ol></li></ol></li><li>If <var>decl</var> is either a <emu-nt>FunctionDeclaration</emu-nt>, a <emu-nt>GeneratorDeclaration</emu-nt>, an <emu-nt>AsyncFunctionDeclaration</emu-nt>, or an <emu-nt>AsyncGeneratorDeclaration</emu-nt>, then<ol><li>Let <var>fn</var> be the sole element of the BoundNames of <var>decl</var>.</li><li>Let <var>fo</var> be InstantiateFunctionObject of <var>decl</var> with arguments <var>env</var> and <var>privateEnv</var>.</li><li>If the host is a web browser or otherwise supports <a href=\"/additional-ecmascript-features-for-web-browsers#sec-block-level-function-declarations-web-legacy-compatibility-semantics\">B.3.2</a>, then<ol><li>If the binding for <var>fn</var> in <var>env</var> is an uninitialized binding, then<ol><li>Perform ! <var>env</var>.InitializeBinding(<var>fn</var>, <var>fo</var>).</li></ol></li><li>Else,<ol><li>Assert: <var>decl</var> is a <emu-nt>FunctionDeclaration</emu-nt>.</li><li>Perform ! <var>env</var>.SetMutableBinding(<var>fn</var>, <var>fo</var>, <b>false</b>).</li></ol></li></ol></li><li>Else,<ol><li>Perform ! <var>env</var>.InitializeBinding(<var>fn</var>, <var>fo</var>).</li></ol></li></ol></li></ol></li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n    ","3.1":"<emu-note>\n        <p><code>let</code> and <code>const</code> declarations define variables that are scoped to the running execution context's LexicalEnvironment. The variables are created when their containing Environment Record is instantiated but may not be accessed in any way until the variable's <emu-nt>LexicalBinding</emu-nt> is evaluated. A variable defined by a <emu-nt>LexicalBinding</emu-nt> with an <emu-nt>Initializer</emu-nt> is assigned the value of its <emu-nt>Initializer</emu-nt>'s <emu-nt>AssignmentExpression</emu-nt> when the <emu-nt>LexicalBinding</emu-nt> is evaluated, not when the variable is created. If a <emu-nt>LexicalBinding</emu-nt> in a <code>let</code> declaration does not have an <emu-nt>Initializer</emu-nt> the variable is assigned the value <b>undefined</b> when the <emu-nt>LexicalBinding</emu-nt> is evaluated.</p>\n      </emu-note>\n      <h2>Syntax</h2>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">LexicalDeclaration</span><span class=\"p\">[In, Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">LetOrConst</span> <span class=\"nt\">BindingList</span><span class=\"p\">[?In, ?Yield, ?Await]</span> <span class=\"t\">;</span>\n\n<span class=\"nt lhs\">LetOrConst</span> <span class=\"geq\">:</span>\n  <span class=\"t\">let</span>\n  <span class=\"t\">const</span>\n\n<span class=\"nt lhs\">BindingList</span><span class=\"p\">[In, Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">LexicalBinding</span><span class=\"p\">[?In, ?Yield, ?Await]</span>\n  <span class=\"nt\">BindingList</span><span class=\"p\">[?In, ?Yield, ?Await]</span> <span class=\"t\">,</span> <span class=\"nt\">LexicalBinding</span><span class=\"p\">[?In, ?Yield, ?Await]</span>\n\n<span class=\"nt lhs\">LexicalBinding</span><span class=\"p\">[In, Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">BindingIdentifier</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"nt\">Initializer</span><span class=\"p\">[?In, ?Yield, ?Await]</span><span class=\"mod\">?</span>\n  <span class=\"nt\">BindingPattern</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"nt\">Initializer</span><span class=\"p\">[?In, ?Yield, ?Await]</span></pre>\n\n      ","3.1.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">LexicalDeclaration</span> <span class=\"geq\">:</span> <span class=\"nt\">LetOrConst</span> <span class=\"nt\">BindingList</span> <span class=\"t\">;</span></pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the BoundNames of <emu-nt>BindingList</emu-nt> contains <b>\"let\"</b>.\n          </li>\n          <li>\n            It is a Syntax Error if the BoundNames of <emu-nt>BindingList</emu-nt> contains any duplicate entries.\n          </li>\n        </ul>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">LexicalBinding</span> <span class=\"geq\">:</span> <span class=\"nt\">BindingIdentifier</span> <span class=\"nt\">Initializer</span><span class=\"mod\">?</span></pre>\n        <ul>\n          <li>\n            It is a Syntax Error if <emu-nt>Initializer</emu-nt> is not present and IsConstantDeclaration of the <emu-nt>LexicalDeclaration</emu-nt> containing this <emu-nt>LexicalBinding</emu-nt> is <b>true</b>.\n          </li>\n        </ul>\n      ","3.1.2":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">LexicalDeclaration</span> <span class=\"geq\">:</span> <span class=\"nt\">LetOrConst</span> <span class=\"nt\">BindingList</span> <span class=\"t\">;</span></pre>\n        <emu-alg><ol><li>Perform ? Evaluation of <emu-nt>BindingList</emu-nt>.</li><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">BindingList</span> <span class=\"geq\">:</span> <span class=\"nt\">BindingList</span> <span class=\"t\">,</span> <span class=\"nt\">LexicalBinding</span></pre>\n        <emu-alg><ol><li>Perform ? Evaluation of <emu-nt>BindingList</emu-nt>.</li><li>Return ? Evaluation of <emu-nt>LexicalBinding</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">LexicalBinding</span> <span class=\"geq\">:</span> <span class=\"nt\">BindingIdentifier</span></pre>\n        <emu-alg><ol><li>Let <var>lhs</var> be ! ResolveBinding(StringValue of <emu-nt>BindingIdentifier</emu-nt>).</li><li>Perform ! InitializeReferencedBinding(<var>lhs</var>, <b>undefined</b>).</li><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n        <emu-note>\n          <p>A static semantics rule ensures that this form of <emu-nt>LexicalBinding</emu-nt> never occurs in a <code>const</code> declaration.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">LexicalBinding</span> <span class=\"geq\">:</span> <span class=\"nt\">BindingIdentifier</span> <span class=\"nt\">Initializer</span></pre>\n        <emu-alg><ol><li>Let <var>bindingId</var> be the StringValue of <emu-nt>BindingIdentifier</emu-nt>.</li><li>Let <var>lhs</var> be ! ResolveBinding(<var>bindingId</var>).</li><li>If IsAnonymousFunctionDefinition(<emu-nt>Initializer</emu-nt>) is <b>true</b>, then<ol><li>Let <var>value</var> be ? NamedEvaluation of <emu-nt>Initializer</emu-nt> with argument <var>bindingId</var>.</li></ol></li><li>Else,<ol><li>Let <var>rhs</var> be ? Evaluation of <emu-nt>Initializer</emu-nt>.</li><li>Let <var>value</var> be ? GetValue(<var>rhs</var>).</li></ol></li><li>Perform ! InitializeReferencedBinding(<var>lhs</var>, <var>value</var>).</li><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">LexicalBinding</span> <span class=\"geq\">:</span> <span class=\"nt\">BindingPattern</span> <span class=\"nt\">Initializer</span></pre>\n        <emu-alg><ol><li>Let <var>rhs</var> be ? Evaluation of <emu-nt>Initializer</emu-nt>.</li><li>Let <var>value</var> be ? GetValue(<var>rhs</var>).</li><li>Let <var>env</var> be the running execution context's LexicalEnvironment.</li><li>Return ? BindingInitialization of <emu-nt>BindingPattern</emu-nt> with arguments <var>value</var> and <var>env</var>.</li></ol></emu-alg>\n      ","3.2":"<emu-note>\n        <p>A <code>var</code> statement declares variables that are scoped to the running execution context's VariableEnvironment. Var variables are created when their containing Environment Record is instantiated and are initialized to <b>undefined</b> when created. Within the scope of any VariableEnvironment a common <emu-nt>BindingIdentifier</emu-nt> may appear in more than one <emu-nt>VariableDeclaration</emu-nt> but those declarations collectively define only one variable. A variable defined by a <emu-nt>VariableDeclaration</emu-nt> with an <emu-nt>Initializer</emu-nt> is assigned the value of its <emu-nt>Initializer</emu-nt>'s <emu-nt>AssignmentExpression</emu-nt> when the <emu-nt>VariableDeclaration</emu-nt> is executed, not when the variable is created.</p>\n      </emu-note>\n      <h2>Syntax</h2>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">VariableStatement</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">var</span> <span class=\"nt\">VariableDeclarationList</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">;</span>\n\n<span class=\"nt lhs\">VariableDeclarationList</span><span class=\"p\">[In, Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">VariableDeclaration</span><span class=\"p\">[?In, ?Yield, ?Await]</span>\n  <span class=\"nt\">VariableDeclarationList</span><span class=\"p\">[?In, ?Yield, ?Await]</span> <span class=\"t\">,</span> <span class=\"nt\">VariableDeclaration</span><span class=\"p\">[?In, ?Yield, ?Await]</span>\n\n<span class=\"nt lhs\">VariableDeclaration</span><span class=\"p\">[In, Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">BindingIdentifier</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"nt\">Initializer</span><span class=\"p\">[?In, ?Yield, ?Await]</span><span class=\"mod\">?</span>\n  <span class=\"nt\">BindingPattern</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"nt\">Initializer</span><span class=\"p\">[?In, ?Yield, ?Await]</span></pre>\n\n      ","3.2.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">VariableStatement</span> <span class=\"geq\">:</span> <span class=\"t\">var</span> <span class=\"nt\">VariableDeclarationList</span> <span class=\"t\">;</span></pre>\n        <emu-alg><ol><li>Perform ? Evaluation of <emu-nt>VariableDeclarationList</emu-nt>.</li><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">VariableDeclarationList</span> <span class=\"geq\">:</span> <span class=\"nt\">VariableDeclarationList</span> <span class=\"t\">,</span> <span class=\"nt\">VariableDeclaration</span></pre>\n        <emu-alg><ol><li>Perform ? Evaluation of <emu-nt>VariableDeclarationList</emu-nt>.</li><li>Return ? Evaluation of <emu-nt>VariableDeclaration</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">VariableDeclaration</span> <span class=\"geq\">:</span> <span class=\"nt\">BindingIdentifier</span></pre>\n        <emu-alg><ol><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">VariableDeclaration</span> <span class=\"geq\">:</span> <span class=\"nt\">BindingIdentifier</span> <span class=\"nt\">Initializer</span></pre>\n        <emu-alg><ol><li>Let <var>bindingId</var> be the StringValue of <emu-nt>BindingIdentifier</emu-nt>.</li><li>Let <var>lhs</var> be ? ResolveBinding(<var>bindingId</var>).</li><li>If IsAnonymousFunctionDefinition(<emu-nt>Initializer</emu-nt>) is <b>true</b>, then<ol><li>Let <var>value</var> be ? NamedEvaluation of <emu-nt>Initializer</emu-nt> with argument <var>bindingId</var>.</li></ol></li><li>Else,<ol><li>Let <var>rhs</var> be ? Evaluation of <emu-nt>Initializer</emu-nt>.</li><li>Let <var>value</var> be ? GetValue(<var>rhs</var>).</li></ol></li><li>Perform ? PutValue(<var>lhs</var>, <var>value</var>).</li><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n        <emu-note>\n          <p>If a <emu-nt>VariableDeclaration</emu-nt> is nested within a with statement and the <emu-nt>BindingIdentifier</emu-nt> in the <emu-nt>VariableDeclaration</emu-nt> is the same as a property name of the binding object of the with statement's Object Environment Record, then step step-vardecllist-evaluation-putvalue will assign <var>value</var> to the property instead of assigning to the VariableEnvironment binding of the <emu-nt>Identifier</emu-nt>.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">VariableDeclaration</span> <span class=\"geq\">:</span> <span class=\"nt\">BindingPattern</span> <span class=\"nt\">Initializer</span></pre>\n        <emu-alg><ol><li>Let <var>rhs</var> be ? Evaluation of <emu-nt>Initializer</emu-nt>.</li><li>Let <var>rVal</var> be ? GetValue(<var>rhs</var>).</li><li>Return ? BindingInitialization of <emu-nt>BindingPattern</emu-nt> with arguments <var>rVal</var> and <b>undefined</b>.</li></ol></emu-alg>\n      ","3.3":"<h2>Syntax</h2>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">BindingPattern</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">ObjectBindingPattern</span><span class=\"p\">[?Yield, ?Await]</span>\n  <span class=\"nt\">ArrayBindingPattern</span><span class=\"p\">[?Yield, ?Await]</span>\n\n<span class=\"nt lhs\">ObjectBindingPattern</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">{</span> <span class=\"t\">}</span>\n  <span class=\"t\">{</span> <span class=\"nt\">BindingRestProperty</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">}</span>\n  <span class=\"t\">{</span> <span class=\"nt\">BindingPropertyList</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">}</span>\n  <span class=\"t\">{</span> <span class=\"nt\">BindingPropertyList</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">,</span> <span class=\"nt\">BindingRestProperty</span><span class=\"p\">[?Yield, ?Await]</span><span class=\"mod\">?</span> <span class=\"t\">}</span>\n\n<span class=\"nt lhs\">ArrayBindingPattern</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">[</span> <span class=\"nt\">Elision</span><span class=\"mod\">?</span> <span class=\"nt\">BindingRestElement</span><span class=\"p\">[?Yield, ?Await]</span><span class=\"mod\">?</span> <span class=\"t\">]</span>\n  <span class=\"t\">[</span> <span class=\"nt\">BindingElementList</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">]</span>\n  <span class=\"t\">[</span> <span class=\"nt\">BindingElementList</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">,</span> <span class=\"nt\">Elision</span><span class=\"mod\">?</span> <span class=\"nt\">BindingRestElement</span><span class=\"p\">[?Yield, ?Await]</span><span class=\"mod\">?</span> <span class=\"t\">]</span>\n\n<span class=\"nt lhs\">BindingRestProperty</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">...</span> <span class=\"nt\">BindingIdentifier</span><span class=\"p\">[?Yield, ?Await]</span>\n\n<span class=\"nt lhs\">BindingPropertyList</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">BindingProperty</span><span class=\"p\">[?Yield, ?Await]</span>\n  <span class=\"nt\">BindingPropertyList</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">,</span> <span class=\"nt\">BindingProperty</span><span class=\"p\">[?Yield, ?Await]</span>\n\n<span class=\"nt lhs\">BindingElementList</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">BindingElisionElement</span><span class=\"p\">[?Yield, ?Await]</span>\n  <span class=\"nt\">BindingElementList</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">,</span> <span class=\"nt\">BindingElisionElement</span><span class=\"p\">[?Yield, ?Await]</span>\n\n<span class=\"nt lhs\">BindingElisionElement</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">Elision</span><span class=\"mod\">?</span> <span class=\"nt\">BindingElement</span><span class=\"p\">[?Yield, ?Await]</span>\n\n<span class=\"nt lhs\">BindingProperty</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">SingleNameBinding</span><span class=\"p\">[?Yield, ?Await]</span>\n  <span class=\"nt\">PropertyName</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">:</span> <span class=\"nt\">BindingElement</span><span class=\"p\">[?Yield, ?Await]</span>\n\n<span class=\"nt lhs\">BindingElement</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">SingleNameBinding</span><span class=\"p\">[?Yield, ?Await]</span>\n  <span class=\"nt\">BindingPattern</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"nt\">Initializer</span><span class=\"p\">[+In, ?Yield, ?Await]</span><span class=\"mod\">?</span>\n\n<span class=\"nt lhs\">SingleNameBinding</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">BindingIdentifier</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"nt\">Initializer</span><span class=\"p\">[+In, ?Yield, ?Await]</span><span class=\"mod\">?</span>\n\n<span class=\"nt lhs\">BindingRestElement</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">...</span> <span class=\"nt\">BindingIdentifier</span><span class=\"p\">[?Yield, ?Await]</span>\n  <span class=\"t\">...</span> <span class=\"nt\">BindingPattern</span><span class=\"p\">[?Yield, ?Await]</span></pre>\n\n      ","3.3.1":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd>It collects a list of all bound property names.</dd>\n        </dl>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">BindingPropertyList</span> <span class=\"geq\">:</span> <span class=\"nt\">BindingPropertyList</span> <span class=\"t\">,</span> <span class=\"nt\">BindingProperty</span></pre>\n        <emu-alg><ol><li>Let <var>boundNames</var> be ? PropertyBindingInitialization of <emu-nt>BindingPropertyList</emu-nt> with arguments <var>value</var> and <var>environment</var>.</li><li>Let <var>nextNames</var> be ? PropertyBindingInitialization of <emu-nt>BindingProperty</emu-nt> with arguments <var>value</var> and <var>environment</var>.</li><li>Return the list-concatenation of <var>boundNames</var> and <var>nextNames</var>.</li></ol></emu-alg>\n\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">BindingProperty</span> <span class=\"geq\">:</span> <span class=\"nt\">SingleNameBinding</span></pre>\n        <emu-alg><ol><li>Let <var>name</var> be the sole element of the BoundNames of <emu-nt>SingleNameBinding</emu-nt>.</li><li>Perform ? KeyedBindingInitialization of <emu-nt>SingleNameBinding</emu-nt> with arguments <var>value</var>, <var>environment</var>, and <var>name</var>.</li><li>Return « <var>name</var> ».</li></ol></emu-alg>\n\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">BindingProperty</span> <span class=\"geq\">:</span> <span class=\"nt\">PropertyName</span> <span class=\"t\">:</span> <span class=\"nt\">BindingElement</span></pre>\n        <emu-alg><ol><li>Let <var>propertyKey</var> be ? Evaluation of <emu-nt>PropertyName</emu-nt>.</li><li>Perform ? KeyedBindingInitialization of <emu-nt>BindingElement</emu-nt> with arguments <var>value</var>, <var>environment</var>, and <var>propertyKey</var>.</li><li>Return « <var>propertyKey</var> ».</li></ol></emu-alg>\n      ","3.3.2":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">BindingRestProperty</span> <span class=\"geq\">:</span> <span class=\"t\">...</span> <span class=\"nt\">BindingIdentifier</span></pre>\n        <emu-alg><ol><li>Let <var>lhs</var> be ? ResolveBinding(StringValue of <emu-nt>BindingIdentifier</emu-nt>, <var>environment</var>).</li><li>Let <var>restObj</var> be OrdinaryObjectCreate(<code class=\"emu-intrinsic\">%Object.prototype%</code>).</li><li>Perform ? CopyDataProperties(<var>restObj</var>, <var>value</var>, <var>excludedNames</var>).</li><li>If <var>environment</var> is <b>undefined</b>, return ? PutValue(<var>lhs</var>, <var>restObj</var>).</li><li>Return ? InitializeReferencedBinding(<var>lhs</var>, <var>restObj</var>).</li></ol></emu-alg>\n      ","3.3.3":"<dl class=\"header\">\n        </dl>\n        <emu-note>\n          <p>When <b>undefined</b> is passed for <var>environment</var> it indicates that a PutValue operation should be used to assign the initialization value. This is the case for formal parameter lists of non-strict functions. In that case the formal parameter bindings are preinitialized in order to deal with the possibility of multiple parameters with the same name.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">BindingElement</span> <span class=\"geq\">:</span> <span class=\"nt\">BindingPattern</span> <span class=\"nt\">Initializer</span><span class=\"mod\">?</span></pre>\n        <emu-alg><ol><li>Let <var>v</var> be ? GetV(<var>value</var>, <var>propertyName</var>).</li><li>If <emu-nt>Initializer</emu-nt> is present and <var>v</var> is <b>undefined</b>, then<ol><li>Let <var>defaultValue</var> be ? Evaluation of <emu-nt>Initializer</emu-nt>.</li><li>Set <var>v</var> to ? GetValue(<var>defaultValue</var>).</li></ol></li><li>Return ? BindingInitialization of <emu-nt>BindingPattern</emu-nt> with arguments <var>v</var> and <var>environment</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">SingleNameBinding</span> <span class=\"geq\">:</span> <span class=\"nt\">BindingIdentifier</span> <span class=\"nt\">Initializer</span><span class=\"mod\">?</span></pre>\n        <emu-alg><ol><li>Let <var>bindingId</var> be the StringValue of <emu-nt>BindingIdentifier</emu-nt>.</li><li>Let <var>lhs</var> be ? ResolveBinding(<var>bindingId</var>, <var>environment</var>).</li><li>Let <var>v</var> be ? GetV(<var>value</var>, <var>propertyName</var>).</li><li>If <emu-nt>Initializer</emu-nt> is present and <var>v</var> is <b>undefined</b>, then<ol><li>If IsAnonymousFunctionDefinition(<emu-nt>Initializer</emu-nt>) is <b>true</b>, then<ol><li>Set <var>v</var> to ? NamedEvaluation of <emu-nt>Initializer</emu-nt> with argument <var>bindingId</var>.</li></ol></li><li>Else,<ol><li>Let <var>defaultValue</var> be ? Evaluation of <emu-nt>Initializer</emu-nt>.</li><li>Set <var>v</var> to ? GetValue(<var>defaultValue</var>).</li></ol></li></ol></li><li>If <var>environment</var> is <b>undefined</b>, return ? PutValue(<var>lhs</var>, <var>v</var>).</li><li>Return ? InitializeReferencedBinding(<var>lhs</var>, <var>v</var>).</li></ol></emu-alg>\n      ","4.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">EmptyStatement</span> <span class=\"geq\">:</span> <span class=\"t\">;</span></pre>\n      <emu-alg><ol><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n    ","5.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">ExpressionStatement</span> <span class=\"geq\">:</span> <span class=\"nt\">Expression</span> <span class=\"t\">;</span></pre>\n      <emu-alg><ol><li>Let <var>exprRef</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Return ? GetValue(<var>exprRef</var>).</li></ol></emu-alg>\n    ","6.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">IfStatement</span> <span class=\"geq\">:</span> <span class=\"t\">if</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span> <span class=\"t\">else</span> <span class=\"nt\">Statement</span></pre>\n      <ul>\n        <li>\n          It is a Syntax Error if IsLabelledFunction(the first <emu-nt>Statement</emu-nt>) is <b>true</b>.\n        </li>\n        <li>\n          It is a Syntax Error if IsLabelledFunction(the second <emu-nt>Statement</emu-nt>) is <b>true</b>.\n        </li>\n      </ul>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">IfStatement</span> <span class=\"geq\">:</span> <span class=\"t\">if</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n      <ul>\n        <li>\n          It is a Syntax Error if IsLabelledFunction(<emu-nt>Statement</emu-nt>) is <b>true</b>.\n        </li>\n      </ul>\n      <emu-note>\n        <p>It is only necessary to apply this rule if the extension specified in <a href=\"/additional-ecmascript-features-for-web-browsers#sec-labelled-function-declarations\">B.3.1</a> is implemented.</p>\n      </emu-note>\n    ","6.2":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">IfStatement</span> <span class=\"geq\">:</span> <span class=\"t\">if</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span> <span class=\"t\">else</span> <span class=\"nt\">Statement</span></pre>\n      <emu-alg><ol><li>Let <var>exprRef</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Let <var>exprValue</var> be ToBoolean(? GetValue(<var>exprRef</var>)).</li><li>If <var>exprValue</var> is <b>true</b>, then<ol><li>Let <var>stmtCompletion</var> be Completion(Evaluation of the first <emu-nt>Statement</emu-nt>).</li></ol></li><li>Else,<ol><li>Let <var>stmtCompletion</var> be Completion(Evaluation of the second <emu-nt>Statement</emu-nt>).</li></ol></li><li>Return ? UpdateEmpty(<var>stmtCompletion</var>, <b>undefined</b>).</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">IfStatement</span> <span class=\"geq\">:</span> <span class=\"t\">if</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n      <emu-alg><ol><li>Let <var>exprRef</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Let <var>exprValue</var> be ToBoolean(? GetValue(<var>exprRef</var>)).</li><li>If <var>exprValue</var> is <b>false</b>, return <b>undefined</b>.</li><li>Let <var>stmtCompletion</var> be Completion(Evaluation of <emu-nt>Statement</emu-nt>).</li><li>Return ? UpdateEmpty(<var>stmtCompletion</var>, <b>undefined</b>).</li></ol></emu-alg>\n    ","7.1":"","7.1.1":"<dl class=\"header\">\n        </dl>\n        <emu-alg><ol><li>If <var>completion</var> is a normal completion, return <b>true</b>.</li><li>If <var>completion</var> is not a continue completion, return <b>false</b>.</li><li>If <var>completion</var>.[[Target]] is <emu-const>empty</emu-const>, return <b>true</b>.</li><li>If <var>labelSet</var> contains <var>completion</var>.[[Target]], return <b>true</b>.</li><li>Return <b>false</b>.</li></ol></emu-alg>\n        <emu-note>\n          <p>Within the <emu-nt>Statement</emu-nt> part of an <emu-nt>IterationStatement</emu-nt> a <emu-nt>ContinueStatement</emu-nt> may be used to begin a new iteration.</p>\n        </emu-note>\n      ","7.1.2":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">IterationStatement</span> <span class=\"geq\">:</span> <span class=\"nt\">DoWhileStatement</span></pre>\n        <emu-alg><ol><li>Return ? DoWhileLoopEvaluation of <emu-nt>DoWhileStatement</emu-nt> with argument <var>labelSet</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">IterationStatement</span> <span class=\"geq\">:</span> <span class=\"nt\">WhileStatement</span></pre>\n        <emu-alg><ol><li>Return ? WhileLoopEvaluation of <emu-nt>WhileStatement</emu-nt> with argument <var>labelSet</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">IterationStatement</span> <span class=\"geq\">:</span> <span class=\"nt\">ForStatement</span></pre>\n        <emu-alg><ol><li>Return ? ForLoopEvaluation of <emu-nt>ForStatement</emu-nt> with argument <var>labelSet</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">IterationStatement</span> <span class=\"geq\">:</span> <span class=\"nt\">ForInOfStatement</span></pre>\n        <emu-alg><ol><li>Return ? ForInOfLoopEvaluation of <emu-nt>ForInOfStatement</emu-nt> with argument <var>labelSet</var>.</li></ol></emu-alg>\n      ","7.2":"<h2>Syntax</h2>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">DoWhileStatement</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">do</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span> <span class=\"t\">while</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"t\">;</span></pre>\n\n      ","7.2.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">DoWhileStatement</span> <span class=\"geq\">:</span> <span class=\"t\">do</span> <span class=\"nt\">Statement</span> <span class=\"t\">while</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"t\">;</span></pre>\n        <ul>\n          <li>\n            It is a Syntax Error if IsLabelledFunction(<emu-nt>Statement</emu-nt>) is <b>true</b>.\n          </li>\n        </ul>\n        <emu-note>\n          <p>It is only necessary to apply this rule if the extension specified in <a href=\"/additional-ecmascript-features-for-web-browsers#sec-labelled-function-declarations\">B.3.1</a> is implemented.</p>\n        </emu-note>\n      ","7.2.2":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">DoWhileStatement</span> <span class=\"geq\">:</span> <span class=\"t\">do</span> <span class=\"nt\">Statement</span> <span class=\"t\">while</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"t\">;</span></pre>\n        <emu-alg><ol><li>Let <var>iterationResult</var> be <b>undefined</b>.</li><li>Repeat,<ol><li>Let <var>stmtResult</var> be Completion(Evaluation of <emu-nt>Statement</emu-nt>).</li><li>If LoopContinues(<var>stmtResult</var>, <var>labelSet</var>) is <b>false</b>, return ? UpdateEmpty(<var>stmtResult</var>, <var>iterationResult</var>).</li><li>If <var>stmtResult</var>.[[Value]] is not <emu-const>empty</emu-const>, set <var>iterationResult</var> to <var>stmtResult</var>.[[Value]].</li><li>Let <var>exprRef</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Let <var>exprValue</var> be ? GetValue(<var>exprRef</var>).</li><li>If ToBoolean(<var>exprValue</var>) is <b>false</b>, return <var>iterationResult</var>.</li></ol></li></ol></emu-alg>\n      ","7.3":"<h2>Syntax</h2>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">WhileStatement</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">while</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span></pre>\n\n      ","7.3.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">WhileStatement</span> <span class=\"geq\">:</span> <span class=\"t\">while</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <ul>\n          <li>\n            It is a Syntax Error if IsLabelledFunction(<emu-nt>Statement</emu-nt>) is <b>true</b>.\n          </li>\n        </ul>\n        <emu-note>\n          <p>It is only necessary to apply this rule if the extension specified in <a href=\"/additional-ecmascript-features-for-web-browsers#sec-labelled-function-declarations\">B.3.1</a> is implemented.</p>\n        </emu-note>\n      ","7.3.2":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">WhileStatement</span> <span class=\"geq\">:</span> <span class=\"t\">while</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <emu-alg><ol><li>Let <var>iterationResult</var> be <b>undefined</b>.</li><li>Repeat,<ol><li>Let <var>exprRef</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Let <var>exprValue</var> be ? GetValue(<var>exprRef</var>).</li><li>If ToBoolean(<var>exprValue</var>) is <b>false</b>, return <var>iterationResult</var>.</li><li>Let <var>stmtResult</var> be Completion(Evaluation of <emu-nt>Statement</emu-nt>).</li><li>If LoopContinues(<var>stmtResult</var>, <var>labelSet</var>) is <b>false</b>, return ? UpdateEmpty(<var>stmtResult</var>, <var>iterationResult</var>).</li><li>If <var>stmtResult</var>.[[Value]] is not <emu-const>empty</emu-const>, set <var>iterationResult</var> to <var>stmtResult</var>.[[Value]].</li></ol></li></ol></emu-alg>\n      ","7.4":"<h2>Syntax</h2>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForStatement</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"p\">[lookahead != `let` `[`]</span> <span class=\"nt\">Expression</span><span class=\"p\">[~In, ?Yield, ?Await]</span><span class=\"mod\">?</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span><span class=\"mod\">?</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span><span class=\"mod\">?</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"t\">var</span> <span class=\"nt\">VariableDeclarationList</span><span class=\"p\">[~In, ?Yield, ?Await]</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span><span class=\"mod\">?</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span><span class=\"mod\">?</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">LexicalDeclaration</span><span class=\"p\">[~In, ?Yield, ?Await]</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span><span class=\"mod\">?</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span><span class=\"mod\">?</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span></pre>\n\n      ","7.4.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">ForStatement</span> <span class=\"geq\">:</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"t\">var</span> <span class=\"nt\">VariableDeclarationList</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">LexicalDeclaration</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <ul>\n          <li>\n            It is a Syntax Error if IsLabelledFunction(<emu-nt>Statement</emu-nt>) is <b>true</b>.\n          </li>\n        </ul>\n        <emu-note>\n          <p>It is only necessary to apply this rule if the extension specified in <a href=\"/additional-ecmascript-features-for-web-browsers#sec-labelled-function-declarations\">B.3.1</a> is implemented.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForStatement</span> <span class=\"geq\">:</span> <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">LexicalDeclaration</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <ul>\n          <li>\n            It is a Syntax Error if any element of the BoundNames of <emu-nt>LexicalDeclaration</emu-nt> also occurs in the VarDeclaredNames of <emu-nt>Statement</emu-nt>.\n          </li>\n        </ul>\n      ","7.4.2":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForStatement</span> <span class=\"geq\">:</span> <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <emu-alg><ol><li>If the first <emu-nt>Expression</emu-nt> is present, then<ol><li>Let <var>exprRef</var> be ? Evaluation of the first <emu-nt>Expression</emu-nt>.</li><li>Perform ? GetValue(<var>exprRef</var>).</li></ol></li><li>If the second <emu-nt>Expression</emu-nt> is present, let <var>test</var> be the second <emu-nt>Expression</emu-nt>; else let <var>test</var> be <emu-const>empty</emu-const>.</li><li>If the third <emu-nt>Expression</emu-nt> is present, let <var>increment</var> be the third <emu-nt>Expression</emu-nt>; else let <var>increment</var> be <emu-const>empty</emu-const>.</li><li>Return ? ForBodyEvaluation(<var>test</var>, <var>increment</var>, <emu-nt>Statement</emu-nt>, « », <var>labelSet</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForStatement</span> <span class=\"geq\">:</span> <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"t\">var</span> <span class=\"nt\">VariableDeclarationList</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <emu-alg><ol><li>Perform ? Evaluation of <emu-nt>VariableDeclarationList</emu-nt>.</li><li>If the first <emu-nt>Expression</emu-nt> is present, let <var>test</var> be the first <emu-nt>Expression</emu-nt>; else let <var>test</var> be <emu-const>empty</emu-const>.</li><li>If the second <emu-nt>Expression</emu-nt> is present, let <var>increment</var> be the second <emu-nt>Expression</emu-nt>; else let <var>increment</var> be <emu-const>empty</emu-const>.</li><li>Return ? ForBodyEvaluation(<var>test</var>, <var>increment</var>, <emu-nt>Statement</emu-nt>, « », <var>labelSet</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForStatement</span> <span class=\"geq\">:</span> <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">LexicalDeclaration</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">;</span> <span class=\"nt\">Expression</span><span class=\"mod\">?</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <emu-alg><ol><li>Let <var>oldEnv</var> be the running execution context's LexicalEnvironment.</li><li>Let <var>loopEnv</var> be NewDeclarativeEnvironment(<var>oldEnv</var>).</li><li>Let <var>isConst</var> be IsConstantDeclaration of <emu-nt>LexicalDeclaration</emu-nt>.</li><li>Let <var>boundNames</var> be the BoundNames of <emu-nt>LexicalDeclaration</emu-nt>.</li><li>For each element <var>dn</var> of <var>boundNames</var>, do<ol><li>If <var>isConst</var> is <b>true</b>, then<ol><li>Perform ! <var>loopEnv</var>.CreateImmutableBinding(<var>dn</var>, <b>true</b>).</li></ol></li><li>Else,<ol><li>Perform ! <var>loopEnv</var>.CreateMutableBinding(<var>dn</var>, <b>false</b>).</li></ol></li></ol></li><li>Set the running execution context's LexicalEnvironment to <var>loopEnv</var>.</li><li>Let <var>forDcl</var> be Completion(Evaluation of <emu-nt>LexicalDeclaration</emu-nt>).</li><li>If <var>forDcl</var> is an abrupt completion, then<ol><li>Set the running execution context's LexicalEnvironment to <var>oldEnv</var>.</li><li>Return ? <var>forDcl</var>.</li></ol></li><li>If <var>isConst</var> is <b>false</b>, let <var>perIterationLets</var> be <var>boundNames</var>; else let <var>perIterationLets</var> be a new empty List.</li><li>If the first <emu-nt>Expression</emu-nt> is present, let <var>test</var> be the first <emu-nt>Expression</emu-nt>; else let <var>test</var> be <emu-const>empty</emu-const>.</li><li>If the second <emu-nt>Expression</emu-nt> is present, let <var>increment</var> be the second <emu-nt>Expression</emu-nt>; else let <var>increment</var> be <emu-const>empty</emu-const>.</li><li>Let <var>bodyResult</var> be Completion(ForBodyEvaluation(<var>test</var>, <var>increment</var>, <emu-nt>Statement</emu-nt>, <var>perIterationLets</var>, <var>labelSet</var>)).</li><li>Set the running execution context's LexicalEnvironment to <var>oldEnv</var>.</li><li>Return ? <var>bodyResult</var>.</li></ol></emu-alg>\n      ","7.4.3":"<dl class=\"header\">\n        </dl>\n        <emu-alg><ol><li>Let <var>iterationResult</var> be <b>undefined</b>.</li><li>Perform ? CreatePerIterationEnvironment(<var>perIterationBindings</var>).</li><li>Repeat,<ol><li>If <var>test</var> is not <emu-const>empty</emu-const>, then<ol><li>Let <var>testRef</var> be ? Evaluation of <var>test</var>.</li><li>Let <var>testValue</var> be ? GetValue(<var>testRef</var>).</li><li>If ToBoolean(<var>testValue</var>) is <b>false</b>, return <var>iterationResult</var>.</li></ol></li><li>Let <var>result</var> be Completion(Evaluation of <var>stmt</var>).</li><li>If LoopContinues(<var>result</var>, <var>labelSet</var>) is <b>false</b>, return ? UpdateEmpty(<var>result</var>, <var>iterationResult</var>).</li><li>If <var>result</var>.[[Value]] is not <emu-const>empty</emu-const>, set <var>iterationResult</var> to <var>result</var>.[[Value]].</li><li>Perform ? CreatePerIterationEnvironment(<var>perIterationBindings</var>).</li><li>If <var>increment</var> is not <emu-const>empty</emu-const>, then<ol><li>Let <var>incRef</var> be ? Evaluation of <var>increment</var>.</li><li>Perform ? GetValue(<var>incRef</var>).</li></ol></li></ol></li></ol></emu-alg>\n      ","7.4.4":"<dl class=\"header\">\n        </dl>\n        <emu-alg><ol><li>If <var>perIterationBindings</var> has any elements, then<ol><li>Let <var>lastIterationEnv</var> be the running execution context's LexicalEnvironment.</li><li>Let <var>outer</var> be <var>lastIterationEnv</var>.[[OuterEnv]].</li><li>Assert: <var>outer</var> is not <b>null</b>.</li><li>Let <var>thisIterationEnv</var> be NewDeclarativeEnvironment(<var>outer</var>).</li><li>For each element <var>bn</var> of <var>perIterationBindings</var>, do<ol><li>Perform ! <var>thisIterationEnv</var>.CreateMutableBinding(<var>bn</var>, <b>false</b>).</li><li>Let <var>lastValue</var> be ? <var>lastIterationEnv</var>.GetBindingValue(<var>bn</var>, <b>true</b>).</li><li>Perform ! <var>thisIterationEnv</var>.InitializeBinding(<var>bn</var>, <var>lastValue</var>).</li></ol></li><li>Set the running execution context's LexicalEnvironment to <var>thisIterationEnv</var>.</li></ol></li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n      ","7.5":"<h2>Syntax</h2>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForInOfStatement</span><span class=\"p\">[Yield, Await, Return]</span> <span class=\"geq\">:</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"p\">[lookahead != `let` `[`]</span> <span class=\"nt\">LeftHandSideExpression</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">in</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"t\">var</span> <span class=\"nt\">ForBinding</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">in</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">ForDeclaration</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">in</span> <span class=\"nt\">Expression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"p\">[lookahead &notin; { `let`, `async` `of` }]</span> <span class=\"nt\">LeftHandSideExpression</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"t\">var</span> <span class=\"nt\">ForBinding</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">ForDeclaration</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"p\">[+Await]</span> <span class=\"t\">for</span> <span class=\"t\">await</span> <span class=\"t\">(</span> <span class=\"p\">[lookahead != `let`]</span> <span class=\"nt\">LeftHandSideExpression</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"p\">[+Await]</span> <span class=\"t\">for</span> <span class=\"t\">await</span> <span class=\"t\">(</span> <span class=\"t\">var</span> <span class=\"nt\">ForBinding</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n  <span class=\"p\">[+Await]</span> <span class=\"t\">for</span> <span class=\"t\">await</span> <span class=\"t\">(</span> <span class=\"nt\">ForDeclaration</span><span class=\"p\">[?Yield, ?Await]</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span><span class=\"p\">[+In, ?Yield, ?Await]</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span><span class=\"p\">[?Yield, ?Await, ?Return]</span>\n\n<span class=\"nt lhs\">ForDeclaration</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">LetOrConst</span> <span class=\"nt\">ForBinding</span><span class=\"p\">[?Yield, ?Await]</span>\n\n<span class=\"nt lhs\">ForBinding</span><span class=\"p\">[Yield, Await]</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">BindingIdentifier</span><span class=\"p\">[?Yield, ?Await]</span>\n  <span class=\"nt\">BindingPattern</span><span class=\"p\">[?Yield, ?Await]</span></pre>\n      <emu-note>\n        <p>This section is extended by Annex <a href=\"/additional-ecmascript-features-for-web-browsers#sec-initializers-in-forin-statement-heads\">B.3.5</a>.</p>\n      </emu-note>\n\n      ","7.5.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">ForInOfStatement</span> <span class=\"geq\">:</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">LeftHandSideExpression</span> <span class=\"t\">in</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"t\">var</span> <span class=\"nt\">ForBinding</span> <span class=\"t\">in</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">ForDeclaration</span> <span class=\"t\">in</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">LeftHandSideExpression</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"t\">var</span> <span class=\"nt\">ForBinding</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">ForDeclaration</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span>\n  <span class=\"t\">for</span> <span class=\"t\">await</span> <span class=\"t\">(</span> <span class=\"nt\">LeftHandSideExpression</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span>\n  <span class=\"t\">for</span> <span class=\"t\">await</span> <span class=\"t\">(</span> <span class=\"t\">var</span> <span class=\"nt\">ForBinding</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span>\n  <span class=\"t\">for</span> <span class=\"t\">await</span> <span class=\"t\">(</span> <span class=\"nt\">ForDeclaration</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <ul>\n          <li>\n            It is a Syntax Error if IsLabelledFunction(<emu-nt>Statement</emu-nt>) is <b>true</b>.\n          </li>\n        </ul>\n        <emu-note>\n          <p>It is only necessary to apply this rule if the extension specified in <a href=\"/additional-ecmascript-features-for-web-browsers#sec-labelled-function-declarations\">B.3.1</a> is implemented.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForInOfStatement</span> <span class=\"geq\">:</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">LeftHandSideExpression</span> <span class=\"t\">in</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">LeftHandSideExpression</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span>\n  <span class=\"t\">for</span> <span class=\"t\">await</span> <span class=\"t\">(</span> <span class=\"nt\">LeftHandSideExpression</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <ul>\n          <li>\n            If <emu-nt>LeftHandSideExpression</emu-nt> is either an <emu-nt>ObjectLiteral</emu-nt> or an <emu-nt>ArrayLiteral</emu-nt>, <emu-nt>LeftHandSideExpression</emu-nt> must cover an <emu-nt>AssignmentPattern</emu-nt>.\n          </li>\n          <li>\n            If <emu-nt>LeftHandSideExpression</emu-nt> is neither an <emu-nt>ObjectLiteral</emu-nt> nor an <emu-nt>ArrayLiteral</emu-nt>, it is a Syntax Error if the AssignmentTargetType of <emu-nt>LeftHandSideExpression</emu-nt> is <emu-const>invalid</emu-const>.\n          </li>\n        </ul>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForInOfStatement</span> <span class=\"geq\">:</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">ForDeclaration</span> <span class=\"t\">in</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span>\n  <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">ForDeclaration</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span>\n  <span class=\"t\">for</span> <span class=\"t\">await</span> <span class=\"t\">(</span> <span class=\"nt\">ForDeclaration</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the BoundNames of <emu-nt>ForDeclaration</emu-nt> contains <b>\"let\"</b>.\n          </li>\n          <li>\n            It is a Syntax Error if any element of the BoundNames of <emu-nt>ForDeclaration</emu-nt> also occurs in the VarDeclaredNames of <emu-nt>Statement</emu-nt>.\n          </li>\n          <li>\n            It is a Syntax Error if the BoundNames of <emu-nt>ForDeclaration</emu-nt> contains any duplicate entries.\n          </li>\n        </ul>\n      ","7.5.2":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">MemberExpression</span> <span class=\"geq\">:</span> <span class=\"nt\">PrimaryExpression</span></pre>\n        <emu-alg><ol><li>If <emu-nt>PrimaryExpression</emu-nt> is either an <emu-nt>ObjectLiteral</emu-nt> or an <emu-nt>ArrayLiteral</emu-nt>, return <b>true</b>.</li><li>Return <b>false</b>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">MemberExpression</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">MemberExpression</span> <span class=\"t\">[</span> <span class=\"nt\">Expression</span> <span class=\"t\">]</span>\n  <span class=\"nt\">MemberExpression</span> <span class=\"t\">.</span> <span class=\"nt\">IdentifierName</span>\n  <span class=\"nt\">MemberExpression</span> <span class=\"nt\">TemplateLiteral</span>\n  <span class=\"nt\">SuperProperty</span>\n  <span class=\"nt\">MetaProperty</span>\n  <span class=\"t\">new</span> <span class=\"nt\">MemberExpression</span> <span class=\"nt\">Arguments</span>\n  <span class=\"nt\">MemberExpression</span> <span class=\"t\">.</span> <span class=\"nt\">PrivateIdentifier</span>\n\n<span class=\"nt lhs\">NewExpression</span> <span class=\"geq\">:</span>\n  <span class=\"t\">new</span> <span class=\"nt\">NewExpression</span>\n\n<span class=\"nt lhs\">LeftHandSideExpression</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">CallExpression</span>\n  <span class=\"nt\">OptionalExpression</span></pre>\n        <emu-alg><ol><li>Return <b>false</b>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForDeclaration</span> <span class=\"geq\">:</span> <span class=\"nt\">LetOrConst</span> <span class=\"nt\">ForBinding</span></pre>\n        <emu-alg><ol><li>Return IsDestructuring of <emu-nt>ForBinding</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForBinding</span> <span class=\"geq\">:</span> <span class=\"nt\">BindingIdentifier</span></pre>\n        <emu-alg><ol><li>Return <b>false</b>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForBinding</span> <span class=\"geq\">:</span> <span class=\"nt\">BindingPattern</span></pre>\n        <emu-alg><ol><li>Return <b>true</b>.</li></ol></emu-alg>\n        <emu-note>\n          <p>This section is extended by Annex <a href=\"/additional-ecmascript-features-for-web-browsers#sec-initializers-in-forin-statement-heads\">B.3.5</a>.</p>\n        </emu-note>\n      ","7.5.3":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForDeclaration</span> <span class=\"geq\">:</span> <span class=\"nt\">LetOrConst</span> <span class=\"nt\">ForBinding</span></pre>\n        <emu-alg><ol><li>Return ? BindingInitialization of <emu-nt>ForBinding</emu-nt> with arguments <var>value</var> and <var>environment</var>.</li></ol></emu-alg>\n      ","7.5.4":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForDeclaration</span> <span class=\"geq\">:</span> <span class=\"nt\">LetOrConst</span> <span class=\"nt\">ForBinding</span></pre>\n        <emu-alg><ol><li>For each element <var>name</var> of the BoundNames of <emu-nt>ForBinding</emu-nt>, do<ol><li>If IsConstantDeclaration of <emu-nt>LetOrConst</emu-nt> is <b>true</b>, then<ol><li>Perform ! <var>environment</var>.CreateImmutableBinding(<var>name</var>, <b>true</b>).</li></ol></li><li>Else,<ol><li>Perform ! <var>environment</var>.CreateMutableBinding(<var>name</var>, <b>false</b>).</li></ol></li></ol></li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n      ","7.5.5":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForInOfStatement</span> <span class=\"geq\">:</span> <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">LeftHandSideExpression</span> <span class=\"t\">in</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <emu-alg><ol><li>Let <var>keyResult</var> be ? ForIn/OfHeadEvaluation(« », <emu-nt>Expression</emu-nt>, <emu-const>enumerate</emu-const>).</li><li>Return ? ForIn/OfBodyEvaluation(<emu-nt>LeftHandSideExpression</emu-nt>, <emu-nt>Statement</emu-nt>, <var>keyResult</var>, <emu-const>enumerate</emu-const>, <emu-const>assignment</emu-const>, <var>labelSet</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForInOfStatement</span> <span class=\"geq\">:</span> <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"t\">var</span> <span class=\"nt\">ForBinding</span> <span class=\"t\">in</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <emu-alg><ol><li>Let <var>keyResult</var> be ? ForIn/OfHeadEvaluation(« », <emu-nt>Expression</emu-nt>, <emu-const>enumerate</emu-const>).</li><li>Return ? ForIn/OfBodyEvaluation(<emu-nt>ForBinding</emu-nt>, <emu-nt>Statement</emu-nt>, <var>keyResult</var>, <emu-const>enumerate</emu-const>, <emu-const>var-binding</emu-const>, <var>labelSet</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForInOfStatement</span> <span class=\"geq\">:</span> <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">ForDeclaration</span> <span class=\"t\">in</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <emu-alg><ol><li>Let <var>keyResult</var> be ? ForIn/OfHeadEvaluation(BoundNames of <emu-nt>ForDeclaration</emu-nt>, <emu-nt>Expression</emu-nt>, <emu-const>enumerate</emu-const>).</li><li>Return ? ForIn/OfBodyEvaluation(<emu-nt>ForDeclaration</emu-nt>, <emu-nt>Statement</emu-nt>, <var>keyResult</var>, <emu-const>enumerate</emu-const>, <emu-const>lexical-binding</emu-const>, <var>labelSet</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForInOfStatement</span> <span class=\"geq\">:</span> <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">LeftHandSideExpression</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <emu-alg><ol><li>Let <var>keyResult</var> be ? ForIn/OfHeadEvaluation(« », <emu-nt>AssignmentExpression</emu-nt>, <emu-const>iterate</emu-const>).</li><li>Return ? ForIn/OfBodyEvaluation(<emu-nt>LeftHandSideExpression</emu-nt>, <emu-nt>Statement</emu-nt>, <var>keyResult</var>, <emu-const>iterate</emu-const>, <emu-const>assignment</emu-const>, <var>labelSet</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForInOfStatement</span> <span class=\"geq\">:</span> <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"t\">var</span> <span class=\"nt\">ForBinding</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <emu-alg><ol><li>Let <var>keyResult</var> be ? ForIn/OfHeadEvaluation(« », <emu-nt>AssignmentExpression</emu-nt>, <emu-const>iterate</emu-const>).</li><li>Return ? ForIn/OfBodyEvaluation(<emu-nt>ForBinding</emu-nt>, <emu-nt>Statement</emu-nt>, <var>keyResult</var>, <emu-const>iterate</emu-const>, <emu-const>var-binding</emu-const>, <var>labelSet</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForInOfStatement</span> <span class=\"geq\">:</span> <span class=\"t\">for</span> <span class=\"t\">(</span> <span class=\"nt\">ForDeclaration</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <emu-alg><ol><li>Let <var>keyResult</var> be ? ForIn/OfHeadEvaluation(BoundNames of <emu-nt>ForDeclaration</emu-nt>, <emu-nt>AssignmentExpression</emu-nt>, <emu-const>iterate</emu-const>).</li><li>Return ? ForIn/OfBodyEvaluation(<emu-nt>ForDeclaration</emu-nt>, <emu-nt>Statement</emu-nt>, <var>keyResult</var>, <emu-const>iterate</emu-const>, <emu-const>lexical-binding</emu-const>, <var>labelSet</var>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForInOfStatement</span> <span class=\"geq\">:</span> <span class=\"t\">for</span> <span class=\"t\">await</span> <span class=\"t\">(</span> <span class=\"nt\">LeftHandSideExpression</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <emu-alg><ol><li>Let <var>keyResult</var> be ? ForIn/OfHeadEvaluation(« », <emu-nt>AssignmentExpression</emu-nt>, <emu-const>async-iterate</emu-const>).</li><li>Return ? ForIn/OfBodyEvaluation(<emu-nt>LeftHandSideExpression</emu-nt>, <emu-nt>Statement</emu-nt>, <var>keyResult</var>, <emu-const>iterate</emu-const>, <emu-const>assignment</emu-const>, <var>labelSet</var>, <emu-const>async</emu-const>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForInOfStatement</span> <span class=\"geq\">:</span> <span class=\"t\">for</span> <span class=\"t\">await</span> <span class=\"t\">(</span> <span class=\"t\">var</span> <span class=\"nt\">ForBinding</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <emu-alg><ol><li>Let <var>keyResult</var> be ? ForIn/OfHeadEvaluation(« », <emu-nt>AssignmentExpression</emu-nt>, <emu-const>async-iterate</emu-const>).</li><li>Return ? ForIn/OfBodyEvaluation(<emu-nt>ForBinding</emu-nt>, <emu-nt>Statement</emu-nt>, <var>keyResult</var>, <emu-const>iterate</emu-const>, <emu-const>var-binding</emu-const>, <var>labelSet</var>, <emu-const>async</emu-const>).</li></ol></emu-alg>\n        <pre class=\"emu-grammar\"><span class=\"nt lhs\">ForInOfStatement</span> <span class=\"geq\">:</span> <span class=\"t\">for</span> <span class=\"t\">await</span> <span class=\"t\">(</span> <span class=\"nt\">ForDeclaration</span> <span class=\"t\">of</span> <span class=\"nt\">AssignmentExpression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n        <emu-alg><ol><li>Let <var>keyResult</var> be ? ForIn/OfHeadEvaluation(BoundNames of <emu-nt>ForDeclaration</emu-nt>, <emu-nt>AssignmentExpression</emu-nt>, <emu-const>async-iterate</emu-const>).</li><li>Return ? ForIn/OfBodyEvaluation(<emu-nt>ForDeclaration</emu-nt>, <emu-nt>Statement</emu-nt>, <var>keyResult</var>, <emu-const>iterate</emu-const>, <emu-const>lexical-binding</emu-const>, <var>labelSet</var>, <emu-const>async</emu-const>).</li></ol></emu-alg>\n        <emu-note>\n          <p>This section is extended by Annex <a href=\"/additional-ecmascript-features-for-web-browsers#sec-initializers-in-forin-statement-heads\">B.3.5</a>.</p>\n        </emu-note>\n      ","7.5.6":"<dl class=\"header\">\n        </dl>\n        <emu-alg><ol><li>Let <var>oldEnv</var> be the running execution context's LexicalEnvironment.</li><li>If <var>uninitializedBoundNames</var> is not empty, then<ol><li>Assert: <var>uninitializedBoundNames</var> has no duplicate entries.</li><li>Let <var>newEnv</var> be NewDeclarativeEnvironment(<var>oldEnv</var>).</li><li>For each String <var>name</var> of <var>uninitializedBoundNames</var>, do<ol><li>Perform ! <var>newEnv</var>.CreateMutableBinding(<var>name</var>, <b>false</b>).</li></ol></li><li>Set the running execution context's LexicalEnvironment to <var>newEnv</var>.</li></ol></li><li>Let <var>exprRef</var> be Completion(Evaluation of <var>expr</var>).</li><li>Set the running execution context's LexicalEnvironment to <var>oldEnv</var>.</li><li>Let <var>exprValue</var> be ? GetValue(? <var>exprRef</var>).</li><li>If <var>iterationKind</var> is <emu-const>enumerate</emu-const>, then<ol><li>If <var>exprValue</var> is either <b>undefined</b> or <b>null</b>, then<ol><li>Return Completion Record { [[Type]]: <emu-const>break</emu-const>, [[Value]]: <emu-const>empty</emu-const>, [[Target]]: <emu-const>empty</emu-const> }.</li></ol></li><li>Let <var>obj</var> be ! ToObject(<var>exprValue</var>).</li><li>Let <var>iterator</var> be EnumerateObjectProperties(<var>obj</var>).</li><li>Let <var>nextMethod</var> be ! GetV(<var>iterator</var>, <b>\"next\"</b>).</li><li>Return the Iterator Record { [[Iterator]]: <var>iterator</var>, [[NextMethod]]: <var>nextMethod</var>, [[Done]]: <b>false</b> }.</li></ol></li><li>Assert: <var>iterationKind</var> is either <emu-const>iterate</emu-const> or <emu-const>async-iterate</emu-const>.</li><li>If <var>iterationKind</var> is <emu-const>async-iterate</emu-const>, let <var>iteratorKind</var> be <emu-const>async</emu-const>.</li><li>Else, let <var>iteratorKind</var> be <emu-const>sync</emu-const>.</li><li>Return ? GetIterator(<var>exprValue</var>, <var>iteratorKind</var>).</li></ol></emu-alg>\n      ","7.5.7":"<dl class=\"header\">\n        </dl>\n        <emu-alg><ol><li>If <var>iteratorKind</var> is not present, set <var>iteratorKind</var> to <emu-const>sync</emu-const>.</li><li>Let <var>oldEnv</var> be the running execution context's LexicalEnvironment.</li><li>Let <var>iterationResult</var> be <b>undefined</b>.</li><li>Let <var>destructuring</var> be IsDestructuring of <var>lhs</var>.</li><li>If <var>destructuring</var> is <b>true</b> and <var>lhsKind</var> is <emu-const>assignment</emu-const>, then<ol><li>Assert: <var>lhs</var> is a <emu-nt>LeftHandSideExpression</emu-nt>.</li><li>Let <var>assignmentPattern</var> be the <emu-nt>AssignmentPattern</emu-nt> that is covered by <var>lhs</var>.</li></ol></li><li>Repeat,<ol><li>Let <var>nextResult</var> be ? Call(<var>iteratorRecord</var>.[[NextMethod]], <var>iteratorRecord</var>.[[Iterator]]).</li><li>If <var>iteratorKind</var> is <emu-const>async</emu-const>, set <var>nextResult</var> to ? Await(<var>nextResult</var>).</li><li>If <var>nextResult</var> is not an Object, throw a <b>TypeError</b> exception.</li><li>Let <var>done</var> be ? IteratorComplete(<var>nextResult</var>).</li><li>If <var>done</var> is <b>true</b>, return <var>iterationResult</var>.</li><li>Let <var>nextValue</var> be ? IteratorValue(<var>nextResult</var>).</li><li>If <var>lhsKind</var> is either <emu-const>assignment</emu-const> or <emu-const>var-binding</emu-const>, then<ol><li>If <var>destructuring</var> is <b>true</b>, then<ol><li>If <var>lhsKind</var> is <emu-const>assignment</emu-const>, then<ol><li>Let <var>status</var> be Completion(DestructuringAssignmentEvaluation of <var>assignmentPattern</var> with argument <var>nextValue</var>).</li></ol></li><li>Else,<ol><li>Assert: <var>lhsKind</var> is <emu-const>var-binding</emu-const>.</li><li>Assert: <var>lhs</var> is a <emu-nt>ForBinding</emu-nt>.</li><li>Let <var>status</var> be Completion(BindingInitialization of <var>lhs</var> with arguments <var>nextValue</var> and <b>undefined</b>).</li></ol></li></ol></li><li>Else,<ol><li>Let <var>lhsRef</var> be Completion(Evaluation of <var>lhs</var>). (It may be evaluated repeatedly.)</li><li>If <var>lhsKind</var> is <emu-const>assignment</emu-const> and the AssignmentTargetType of <var>lhs</var> is <emu-const>web-compat</emu-const>, throw a <b>ReferenceError</b> exception.</li><li>If <var>lhsRef</var> is an abrupt completion, then<ol><li>Let <var>status</var> be <var>lhsRef</var>.</li></ol></li><li>Else,<ol><li>Let <var>status</var> be Completion(PutValue(<var>lhsRef</var>.[[Value]], <var>nextValue</var>)).</li></ol></li></ol></li></ol></li><li>Else,<ol><li>Assert: <var>lhsKind</var> is <emu-const>lexical-binding</emu-const>.</li><li>Assert: <var>lhs</var> is a <emu-nt>ForDeclaration</emu-nt>.</li><li>Let <var>iterationEnv</var> be NewDeclarativeEnvironment(<var>oldEnv</var>).</li><li>Perform ForDeclarationBindingInstantiation of <var>lhs</var> with argument <var>iterationEnv</var>.</li><li>Set the running execution context's LexicalEnvironment to <var>iterationEnv</var>.</li><li>If <var>destructuring</var> is <b>true</b>, then<ol><li>Let <var>status</var> be Completion(ForDeclarationBindingInitialization of <var>lhs</var> with arguments <var>nextValue</var> and <var>iterationEnv</var>).</li></ol></li><li>Else,<ol><li>Assert: <var>lhs</var> binds a single name.</li><li>Let <var>lhsName</var> be the sole element of the BoundNames of <var>lhs</var>.</li><li>Let <var>lhsRef</var> be ! ResolveBinding(<var>lhsName</var>).</li><li>Let <var>status</var> be Completion(InitializeReferencedBinding(<var>lhsRef</var>, <var>nextValue</var>)).</li></ol></li></ol></li><li>If <var>status</var> is an abrupt completion, then<ol><li>Set the running execution context's LexicalEnvironment to <var>oldEnv</var>.</li><li>If <var>iterationKind</var> is <emu-const>enumerate</emu-const>, return ? <var>status</var>.</li><li>Assert: <var>iterationKind</var> is <emu-const>iterate</emu-const>.</li><li>If <var>iteratorKind</var> is <emu-const>async</emu-const>, return ? AsyncIteratorClose(<var>iteratorRecord</var>, <var>status</var>).</li><li>Return ? IteratorClose(<var>iteratorRecord</var>, <var>status</var>).</li></ol></li><li>Let <var>result</var> be Completion(Evaluation of <var>stmt</var>).</li><li>Set the running execution context's LexicalEnvironment to <var>oldEnv</var>.</li><li>If LoopContinues(<var>result</var>, <var>labelSet</var>) is <b>false</b>, then<ol><li>Set <var>status</var> to Completion(UpdateEmpty(<var>result</var>, <var>iterationResult</var>)).</li><li>If <var>iterationKind</var> is <emu-const>enumerate</emu-const>, return ? <var>status</var>.</li><li>Assert: <var>iterationKind</var> is <emu-const>iterate</emu-const>.</li><li>If <var>iteratorKind</var> is <emu-const>async</emu-const>, return ? AsyncIteratorClose(<var>iteratorRecord</var>, <var>status</var>).</li><li>Return ? IteratorClose(<var>iteratorRecord</var>, <var>status</var>).</li></ol></li><li>If <var>result</var>.[[Value]] is not <emu-const>empty</emu-const>, set <var>iterationResult</var> to <var>result</var>.[[Value]].</li></ol></li></ol></emu-alg>\n      ","7.5.8":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">BindingIdentifier</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">Identifier</span>\n  <span class=\"t\">yield</span>\n  <span class=\"t\">await</span></pre>\n        <emu-alg><ol><li>Let <var>bindingId</var> be the StringValue of <emu-nt>BindingIdentifier</emu-nt>.</li><li>Return ? ResolveBinding(<var>bindingId</var>).</li></ol></emu-alg>\n      ","7.5.9":"<dl class=\"header\">\n        </dl>\n        <emu-alg><ol><li>Return an iterator object whose <code>next</code> method iterates over all the String-valued keys of enumerable properties of <var>obj</var>. The iterator object is never directly accessible to ECMAScript code. The mechanics and order of enumerating the properties is not specified but must conform to the rules specified below.</li></ol></emu-alg>\n        <p>The iterator's <code>throw</code> and <code>return</code> methods are <b>null</b> and are never invoked. The iterator's <code>next</code> method processes object properties to determine whether the property key should be returned as an iterator value. Returned property keys do not include keys that are Symbols. Properties of the target object may be deleted during enumeration. A property that is deleted before it is processed by the iterator's <code>next</code> method is ignored. If new properties are added to the target object during enumeration, the newly added properties are not guaranteed to be processed in the active enumeration. A property name will be returned by the iterator's <code>next</code> method at most once in any enumeration.</p>\n        <p>Enumerating the properties of the target object includes enumerating properties of its prototype, and the prototype of the prototype, and so on, recursively; but a property of a prototype is not processed if it has the same name as a property that has already been processed by the iterator's <code>next</code> method. The values of [[Enumerable]] attributes are not considered when determining if a property of a prototype object has already been processed. The enumerable property names of prototype objects must be obtained by invoking EnumerateObjectProperties passing the prototype object as the argument. EnumerateObjectProperties must obtain the own property keys of the target object by calling its [[OwnPropertyKeys]] internal method. Property attributes of the target object must be obtained by calling its [[GetOwnProperty]] internal method.</p>\n        <p>In addition, if neither <var>obj</var> nor any object in its prototype chain is a Proxy exotic object, TypedArray, module namespace exotic object, or implementation provided exotic object, then the iterator must behave as would the iterator given by CreateForInIterator(<var>obj</var>) until one of the following occurs:</p>\n        <ul>\n          <li>the value of the [[Prototype]] internal slot of <var>obj</var> or an object in its prototype chain changes,</li>\n          <li>a property is removed from <var>obj</var> or an object in its prototype chain,</li>\n          <li>a property is added to an object in <var>obj</var>'s prototype chain, or</li>\n          <li>the value of the [[Enumerable]] attribute of a property of <var>obj</var> or an object in its prototype chain changes.</li>\n        </ul>\n\n        <emu-note>\n          <p>ECMAScript implementations are not required to implement the algorithm in <a href=\"/ecmascript-language-statements-and-declarations#sec-%foriniteratorprototype%.next\">14.7.5.10.2.1</a> directly. They may choose any implementation whose behaviour will not deviate from that algorithm unless one of the constraints in the previous paragraph is violated.</p>\n          <p>The following is an informative definition of an ECMAScript generator function that conforms to these rules:</p>\n          <pre><code class=\"javascript\">\n            function* EnumerateObjectProperties(obj) {\n              const visited = new Set();\n              for (const key of Reflect.ownKeys(obj)) {\n                if (typeof key === \"symbol\") continue;\n                const desc = Reflect.getOwnPropertyDescriptor(obj, key);\n                if (desc) {\n                  visited.add(key);\n                  if (desc.enumerable) yield key;\n                }\n              }\n              const proto = Reflect.getPrototypeOf(obj);\n              if (proto === null) return;\n              for (const protoKey of EnumerateObjectProperties(proto)) {\n                if (!visited.has(protoKey)) yield protoKey;\n              }\n            }\n          </code></pre>\n        </emu-note>\n        <emu-note>\n          The list of exotic objects for which implementations are not required to match CreateForInIterator was chosen because implementations historically differed in behaviour for those cases, and agreed in all others.\n        </emu-note>\n      ","7.5.10":"<p>A <dfn variants=\"For-In Iterator object,For-In Iterator objects\">For-In Iterator</dfn> is an object that represents a specific iteration over some specific object. For-In Iterator objects are never directly accessible to ECMAScript code; they exist solely to illustrate the behaviour of EnumerateObjectProperties.</p>\n\n        ","7.5.10.1":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd>It is used to create a For-In Iterator object which iterates over the own and inherited enumerable string properties of <var>object</var> in a specific order.</dd>\n          </dl>\n          <emu-alg><ol><li>Let <var>iterator</var> be OrdinaryObjectCreate(<code class=\"emu-intrinsic\">%ForInIteratorPrototype%</code>, « [[Object]], [[ObjectWasVisited]], [[VisitedKeys]], [[RemainingKeys]] »).</li><li>Set <var>iterator</var>.[[Object]] to <var>object</var>.</li><li>Set <var>iterator</var>.[[ObjectWasVisited]] to <b>false</b>.</li><li>Set <var>iterator</var>.[[VisitedKeys]] to a new empty List.</li><li>Set <var>iterator</var>.[[RemainingKeys]] to a new empty List.</li><li>Return <var>iterator</var>.</li></ol></emu-alg>\n        ","7.5.10.2":"<p>The <dfn><code class=\"emu-intrinsic\">%ForInIteratorPrototype%</code></dfn> object:</p>\n          <ul>\n            <li>has properties that are inherited by all For-In Iterator objects.</li>\n            <li>is an ordinary object.</li>\n            <li>has a [[Prototype]] internal slot whose value is <code class=\"emu-intrinsic\">%Iterator.prototype%</code>.</li>\n            <li>is never directly accessible to ECMAScript code.</li>\n            <li>has the following properties:</li>\n          </ul>\n\n          ","7.5.10.2.1":"<emu-alg><ol><li>Let <var>iter</var> be the <b>this</b> value.</li><li>Assert: <var>iter</var> is an Object.</li><li>Assert: <var>iter</var> has all of the internal slots of a For-In Iterator instance (<a href=\"/ecmascript-language-statements-and-declarations#sec-properties-of-for-in-iterator-instances\">14.7.5.10.3</a>).</li><li>Let <var>object</var> be <var>iter</var>.[[Object]].</li><li>Repeat,<ol><li>If <var>iter</var>.[[ObjectWasVisited]] is <b>false</b>, then<ol><li>Let <var>keys</var> be ? <emu-meta effects=\"user-code\"><var>object</var>.[[OwnPropertyKeys]]()</emu-meta>.</li><li>For each element <var>key</var> of <var>keys</var>, do<ol><li>If <var>key</var> is a String, then<ol><li>Append <var>key</var> to <var>iter</var>.[[RemainingKeys]].</li></ol></li></ol></li><li>Set <var>iter</var>.[[ObjectWasVisited]] to <b>true</b>.</li></ol></li><li>Repeat, while <var>iter</var>.[[RemainingKeys]] is not empty,<ol><li>Let <var>key</var> be the first element of <var>iter</var>.[[RemainingKeys]].</li><li>Remove the first element from <var>iter</var>.[[RemainingKeys]].</li><li>If <var>iter</var>.[[VisitedKeys]] does not contain <var>key</var>, then<ol><li>Let <var>desc</var> be ? <emu-meta effects=\"user-code\"><var>object</var>.[[GetOwnProperty]](<var>key</var>)</emu-meta>.</li><li>If <var>desc</var> is not <b>undefined</b>, then<ol><li>Append <var>key</var> to <var>iter</var>.[[VisitedKeys]].</li><li>If <var>desc</var>.[[Enumerable]] is <b>true</b>, return CreateIteratorResultObject(<var>key</var>, <b>false</b>).</li></ol></li></ol></li></ol></li><li>Set <var>object</var> to ? <emu-meta effects=\"user-code\"><var>object</var>.[[GetPrototypeOf]]()</emu-meta>.</li><li>Set <var>iter</var>.[[Object]] to <var>object</var>.</li><li>Set <var>iter</var>.[[ObjectWasVisited]] to <b>false</b>.</li><li>If <var>object</var> is <b>null</b>, return CreateIteratorResultObject(<b>undefined</b>, <b>true</b>).</li></ol></li></ol></emu-alg>\n          ","7.5.10.3":"<p>For-In Iterator instances are ordinary objects that inherit properties from the <code class=\"emu-intrinsic\">%ForInIteratorPrototype%</code> intrinsic object. For-In Iterator instances are initially created with the internal slots listed in table-for-in-iterator-instance-slots.</p>\n          <emu-table id=\"table-for-in-iterator-instance-slots\" caption=\"Internal Slots of For-In Iterator Instances\">\n            <table>\n              <thead>\n                <tr>\n                  <th>\n                    Internal Slot\n                  </th>\n                  <th>\n                    Type\n                  </th>\n                  <th>\n                    Description\n                  </th>\n                </tr>\n              </thead>\n              <tr>\n                <td>\n                  [[Object]]\n                </td>\n                <td>\n                  an Object\n                </td>\n                <td>\n                  The Object value whose properties are being iterated.\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  [[ObjectWasVisited]]\n                </td>\n                <td>\n                  a Boolean\n                </td>\n                <td>\n                  <b>true</b> if the iterator has invoked [[OwnPropertyKeys]] on [[Object]], <b>false</b> otherwise.\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  [[VisitedKeys]]\n                </td>\n                <td>\n                  a List of Strings\n                </td>\n                <td>\n                  The values that have been emitted by this iterator thus far.\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  [[RemainingKeys]]\n                </td>\n                <td>\n                  a List of Strings\n                </td>\n                <td>\n                  The values remaining to be emitted for the current object, before iterating the properties of its prototype (if its prototype is not <b>null</b>).\n                </td>\n              </tr>\n            </table>\n          </emu-table>\n        ","8.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">ContinueStatement</span> <span class=\"geq\">:</span>\n  <span class=\"t\">continue</span> <span class=\"t\">;</span>\n  <span class=\"t\">continue</span> <span class=\"nt\">LabelIdentifier</span> <span class=\"t\">;</span></pre>\n      <ul>\n        <li>\n          It is a Syntax Error if this <emu-nt>ContinueStatement</emu-nt> is not nested, directly or indirectly (but not crossing function or <code>static</code> initialization block boundaries), within an <emu-nt>IterationStatement</emu-nt>.\n        </li>\n      </ul>\n    ","8.2":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">ContinueStatement</span> <span class=\"geq\">:</span> <span class=\"t\">continue</span> <span class=\"t\">;</span></pre>\n      <emu-alg><ol><li>Return Completion Record { [[Type]]: <emu-const>continue</emu-const>, [[Value]]: <emu-const>empty</emu-const>, [[Target]]: <emu-const>empty</emu-const> }.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">ContinueStatement</span> <span class=\"geq\">:</span> <span class=\"t\">continue</span> <span class=\"nt\">LabelIdentifier</span> <span class=\"t\">;</span></pre>\n      <emu-alg><ol><li>Let <var>label</var> be the StringValue of <emu-nt>LabelIdentifier</emu-nt>.</li><li>Return Completion Record { [[Type]]: <emu-const>continue</emu-const>, [[Value]]: <emu-const>empty</emu-const>, [[Target]]: <var>label</var> }.</li></ol></emu-alg>\n    ","9.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">BreakStatement</span> <span class=\"geq\">:</span> <span class=\"t\">break</span> <span class=\"t\">;</span></pre>\n      <ul>\n        <li>\n          It is a Syntax Error if this <emu-nt>BreakStatement</emu-nt> is not nested, directly or indirectly (but not crossing function or <code>static</code> initialization block boundaries), within an <emu-nt>IterationStatement</emu-nt> or a <emu-nt>SwitchStatement</emu-nt>.\n        </li>\n      </ul>\n    ","9.2":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">BreakStatement</span> <span class=\"geq\">:</span> <span class=\"t\">break</span> <span class=\"t\">;</span></pre>\n      <emu-alg><ol><li>Return Completion Record { [[Type]]: <emu-const>break</emu-const>, [[Value]]: <emu-const>empty</emu-const>, [[Target]]: <emu-const>empty</emu-const> }.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">BreakStatement</span> <span class=\"geq\">:</span> <span class=\"t\">break</span> <span class=\"nt\">LabelIdentifier</span> <span class=\"t\">;</span></pre>\n      <emu-alg><ol><li>Let <var>label</var> be the StringValue of <emu-nt>LabelIdentifier</emu-nt>.</li><li>Return Completion Record { [[Type]]: <emu-const>break</emu-const>, [[Value]]: <emu-const>empty</emu-const>, [[Target]]: <var>label</var> }.</li></ol></emu-alg>\n    ","10.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">ReturnStatement</span> <span class=\"geq\">:</span> <span class=\"t\">return</span> <span class=\"t\">;</span></pre>\n      <emu-alg><ol><li>Return ReturnCompletion(<b>undefined</b>).</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">ReturnStatement</span> <span class=\"geq\">:</span> <span class=\"t\">return</span> <span class=\"nt\">Expression</span> <span class=\"t\">;</span></pre>\n      <emu-alg><ol><li>Let <var>exprRef</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Let <var>exprValue</var> be ? GetValue(<var>exprRef</var>).</li><li>If GetGeneratorKind() is <emu-const>async</emu-const>, set <var>exprValue</var> to ? Await(<var>exprValue</var>).</li><li>Return ReturnCompletion(<var>exprValue</var>).</li></ol></emu-alg>\n    ","11.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">WithStatement</span> <span class=\"geq\">:</span> <span class=\"t\">with</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n      <ul>\n        <li>\n          It is a Syntax Error if IsStrict(this production) is <b>true</b>.\n        </li>\n        <li>\n          It is a Syntax Error if IsLabelledFunction(<emu-nt>Statement</emu-nt>) is <b>true</b>.\n        </li>\n      </ul>\n      <emu-note>\n        <p>It is only necessary to apply the second rule if the extension specified in <a href=\"/additional-ecmascript-features-for-web-browsers#sec-labelled-function-declarations\">B.3.1</a> is implemented.</p>\n      </emu-note>\n    ","11.2":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">WithStatement</span> <span class=\"geq\">:</span> <span class=\"t\">with</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">Statement</span></pre>\n      <emu-alg><ol><li>Let <var>val</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Let <var>obj</var> be ? ToObject(? GetValue(<var>val</var>)).</li><li>Let <var>oldEnv</var> be the running execution context's LexicalEnvironment.</li><li>Let <var>newEnv</var> be NewObjectEnvironment(<var>obj</var>, <b>true</b>, <var>oldEnv</var>).</li><li>Set the running execution context's LexicalEnvironment to <var>newEnv</var>.</li><li>Let <var>stmtCompletion</var> be Completion(Evaluation of <emu-nt>Statement</emu-nt>).</li><li>Set the running execution context's LexicalEnvironment to <var>oldEnv</var>.</li><li>Return ? UpdateEmpty(<var>stmtCompletion</var>, <b>undefined</b>).</li></ol></emu-alg>\n      <emu-note>\n        <p>No matter how control leaves the embedded <emu-nt>Statement</emu-nt>, whether normally or by some form of abrupt completion or exception, the LexicalEnvironment is always restored to its former state.</p>\n      </emu-note>\n    ","12.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">SwitchStatement</span> <span class=\"geq\">:</span> <span class=\"t\">switch</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">CaseBlock</span></pre>\n      <ul>\n        <li>\n          <p>It is a Syntax Error if the LexicallyDeclaredNames of <emu-nt>CaseBlock</emu-nt> contains any duplicate entries<span normative-optional>, unless the host is a web browser or otherwise supports <a href=\"/additional-ecmascript-features-for-web-browsers#sec-block-level-function-declarations-web-legacy-compatibility-semantics\">B.3.2</a>, and both of the following conditions are true:</span></p>\n          <ul normative-optional>\n            <li>IsStrict(this production) is <b>false</b>.</li>\n            <li>The duplicate entries are only bound by FunctionDeclarations.</li>\n          </ul>\n        </li>\n        <li>\n          It is a Syntax Error if any element of the LexicallyDeclaredNames of <emu-nt>CaseBlock</emu-nt> also occurs in the VarDeclaredNames of <emu-nt>CaseBlock</emu-nt>.\n        </li>\n      </ul>\n    ","12.2":"<dl class=\"header\">\n      </dl>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">CaseBlock</span> <span class=\"geq\">:</span> <span class=\"t\">{</span> <span class=\"t\">}</span></pre>\n      <emu-alg><ol><li>Return <b>undefined</b>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">CaseBlock</span> <span class=\"geq\">:</span> <span class=\"t\">{</span> <span class=\"nt\">CaseClauses</span> <span class=\"t\">}</span></pre>\n      <emu-alg><ol><li>Let <var>resultValue</var> be <b>undefined</b>.</li><li>Let <var>caseClauses</var> be the List of <emu-nt>CaseClause</emu-nt> items in <emu-nt>CaseClauses</emu-nt>, in source text order.</li><li>Let <var>found</var> be <b>false</b>.</li><li>For each <emu-nt>CaseClause</emu-nt> <var>clause</var> of <var>caseClauses</var>, do<ol><li>If <var>found</var> is <b>false</b>, then<ol><li>Set <var>found</var> to ? CaseClauseIsSelected(<var>clause</var>, <var>input</var>).</li></ol></li><li>If <var>found</var> is <b>true</b>, then<ol><li>Let <var>completion</var> be Completion(Evaluation of <var>clause</var>).</li><li>If <var>completion</var>.[[Value]] is not <emu-const>empty</emu-const>, set <var>resultValue</var> to <var>completion</var>.[[Value]].</li><li>If <var>completion</var> is an abrupt completion, return ? UpdateEmpty(<var>completion</var>, <var>resultValue</var>).</li></ol></li></ol></li><li>Return <var>resultValue</var>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">CaseBlock</span> <span class=\"geq\">:</span> <span class=\"t\">{</span> <span class=\"nt\">CaseClauses</span><span class=\"mod\">?</span> <span class=\"nt\">DefaultClause</span> <span class=\"nt\">CaseClauses</span><span class=\"mod\">?</span> <span class=\"t\">}</span></pre>\n      <emu-alg><ol><li>Let <var>resultValue</var> be <b>undefined</b>.</li><li>If the first <emu-nt>CaseClauses</emu-nt> is present, then<ol><li>Let <var>caseClauses</var> be the List of <emu-nt>CaseClause</emu-nt> items in the first <emu-nt>CaseClauses</emu-nt>, in source text order.</li></ol></li><li>Else,<ol><li>Let <var>caseClauses</var> be a new empty List.</li></ol></li><li>Let <var>found</var> be <b>false</b>.</li><li>For each <emu-nt>CaseClause</emu-nt> <var>clause</var> of <var>caseClauses</var>, do<ol><li>If <var>found</var> is <b>false</b>, then<ol><li>Set <var>found</var> to ? CaseClauseIsSelected(<var>clause</var>, <var>input</var>).</li></ol></li><li>If <var>found</var> is <b>true</b>, then<ol><li>Let <var>completion</var> be Completion(Evaluation of <var>clause</var>).</li><li>If <var>completion</var>.[[Value]] is not <emu-const>empty</emu-const>, set <var>resultValue</var> to <var>completion</var>.[[Value]].</li><li>If <var>completion</var> is an abrupt completion, return ? UpdateEmpty(<var>completion</var>, <var>resultValue</var>).</li></ol></li></ol></li><li>Let <var>foundInB</var> be <b>false</b>.</li><li>If the second <emu-nt>CaseClauses</emu-nt> is present, then<ol><li>Let <var>secondCaseClauses</var> be the List of <emu-nt>CaseClause</emu-nt> items in the second <emu-nt>CaseClauses</emu-nt>, in source text order.</li></ol></li><li>Else,<ol><li>Let <var>secondCaseClauses</var> be a new empty List.</li></ol></li><li>If <var>found</var> is <b>false</b>, then<ol><li>For each <emu-nt>CaseClause</emu-nt> <var>clause</var> of <var>secondCaseClauses</var>, do<ol><li>If <var>foundInB</var> is <b>false</b>, then<ol><li>Set <var>foundInB</var> to ? CaseClauseIsSelected(<var>clause</var>, <var>input</var>).</li></ol></li><li>If <var>foundInB</var> is <b>true</b>, then<ol><li>Let <var>completion</var> be Completion(Evaluation of <emu-nt>CaseClause</emu-nt> <var>clause</var>).</li><li>If <var>completion</var>.[[Value]] is not <emu-const>empty</emu-const>, set <var>resultValue</var> to <var>completion</var>.[[Value]].</li><li>If <var>completion</var> is an abrupt completion, return ? UpdateEmpty(<var>completion</var>, <var>resultValue</var>).</li></ol></li></ol></li></ol></li><li>If <var>foundInB</var> is <b>true</b>, return <var>resultValue</var>.</li><li>Let <var>defaultR</var> be Completion(Evaluation of <emu-nt>DefaultClause</emu-nt>).</li><li>If <var>defaultR</var>.[[Value]] is not <emu-const>empty</emu-const>, set <var>resultValue</var> to <var>defaultR</var>.[[Value]].</li><li>If <var>defaultR</var> is an abrupt completion, return ? UpdateEmpty(<var>defaultR</var>, <var>resultValue</var>).</li><li>NOTE: The following is another complete iteration of the second <emu-nt>CaseClauses</emu-nt>.</li><li>For each <emu-nt>CaseClause</emu-nt> <var>clause</var> of <var>secondCaseClauses</var>, do<ol><li>Let <var>completion</var> be Completion(Evaluation of <emu-nt>CaseClause</emu-nt> <var>clause</var>).</li><li>If <var>completion</var>.[[Value]] is not <emu-const>empty</emu-const>, set <var>resultValue</var> to <var>completion</var>.[[Value]].</li><li>If <var>completion</var> is an abrupt completion, return ? UpdateEmpty(<var>completion</var>, <var>resultValue</var>).</li></ol></li><li>Return <var>resultValue</var>.</li></ol></emu-alg>\n    ","12.3":"<dl class=\"header\">\n        <dt>description</dt>\n        <dd>It determines whether <var>constructor</var> matches <var>input</var>.</dd>\n      </dl>\n      <emu-alg><ol><li>Assert: <var>constructor</var> is an instance of the production <code class=\"emu-grammar\"><span class=\"nt lhs\">CaseClause</span> <span class=\"geq\">:</span> <span class=\"t\">case</span> <span class=\"nt\">Expression</span> <span class=\"t\">:</span> <span class=\"nt\">StatementList</span><span class=\"mod\">?</span></code>.</li><li>Let <var>exprRef</var> be ? Evaluation of the <emu-nt>Expression</emu-nt> of <var>constructor</var>.</li><li>Let <var>clauseSelector</var> be ? GetValue(<var>exprRef</var>).</li><li>Return IsStrictlyEqual(<var>input</var>, <var>clauseSelector</var>).</li></ol></emu-alg>\n      <emu-note>\n        <p>This operation does not execute <var>constructor</var>'s <emu-nt>StatementList</emu-nt> (if any). The <emu-nt>CaseBlock</emu-nt> algorithm uses its return value to determine which <emu-nt>StatementList</emu-nt> to start executing.</p>\n      </emu-note>\n    ","12.4":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">SwitchStatement</span> <span class=\"geq\">:</span> <span class=\"t\">switch</span> <span class=\"t\">(</span> <span class=\"nt\">Expression</span> <span class=\"t\">)</span> <span class=\"nt\">CaseBlock</span></pre>\n      <emu-alg><ol><li>Let <var>exprRef</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Let <var>switchValue</var> be ? GetValue(<var>exprRef</var>).</li><li>Let <var>oldEnv</var> be the running execution context's LexicalEnvironment.</li><li>Let <var>blockEnv</var> be NewDeclarativeEnvironment(<var>oldEnv</var>).</li><li>Perform BlockDeclarationInstantiation(<emu-nt>CaseBlock</emu-nt>, <var>blockEnv</var>).</li><li>Set the running execution context's LexicalEnvironment to <var>blockEnv</var>.</li><li>Let <var>blockResult</var> be Completion(CaseBlockEvaluation of <emu-nt>CaseBlock</emu-nt> with argument <var>switchValue</var>).</li><li>Set the running execution context's LexicalEnvironment to <var>oldEnv</var>.</li><li>Return <var>blockResult</var>.</li></ol></emu-alg>\n      <emu-note>\n        <p>No matter how control leaves the <emu-nt>SwitchStatement</emu-nt> the LexicalEnvironment is always restored to its former state.</p>\n      </emu-note>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">CaseClause</span> <span class=\"geq\">:</span> <span class=\"t\">case</span> <span class=\"nt\">Expression</span> <span class=\"t\">:</span></pre>\n      <emu-alg><ol><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">CaseClause</span> <span class=\"geq\">:</span> <span class=\"t\">case</span> <span class=\"nt\">Expression</span> <span class=\"t\">:</span> <span class=\"nt\">StatementList</span></pre>\n      <emu-alg><ol><li>Return ? Evaluation of <emu-nt>StatementList</emu-nt>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">DefaultClause</span> <span class=\"geq\">:</span> <span class=\"t\">default</span> <span class=\"t\">:</span></pre>\n      <emu-alg><ol><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">DefaultClause</span> <span class=\"geq\">:</span> <span class=\"t\">default</span> <span class=\"t\">:</span> <span class=\"nt\">StatementList</span></pre>\n      <emu-alg><ol><li>Return ? Evaluation of <emu-nt>StatementList</emu-nt>.</li></ol></emu-alg>\n    ","13.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">LabelledItem</span> <span class=\"geq\">:</span> <span class=\"nt\">FunctionDeclaration</span></pre>\n      <ul>\n        <li>\n          It is a Syntax Error if any source text is matched by this production<span normative-optional>, unless that source text is non-strict code and the host is a web browser or otherwise supports <a href=\"/additional-ecmascript-features-for-web-browsers#sec-labelled-function-declarations\">B.3.1</a></span>.\n        </li>\n      </ul>\n    ","13.2":"<dl class=\"header\">\n      </dl>\n      <emu-alg><ol><li>If <var>stmt</var> is not a <emu-nt>LabelledStatement</emu-nt>, return <b>false</b>.</li><li>Let <var>item</var> be the <emu-nt>LabelledItem</emu-nt> of <var>stmt</var>.</li><li>If <var>item</var> is <code class=\"emu-grammar\"><span class=\"nt lhs\">LabelledItem</span> <span class=\"geq\">:</span> <span class=\"nt\">FunctionDeclaration</span></code>, return <b>true</b>.</li><li>Let <var>subStmt</var> be the <emu-nt>Statement</emu-nt> of <var>item</var>.</li><li>Return IsLabelledFunction(<var>subStmt</var>).</li></ol></emu-alg>\n    ","13.3":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">LabelledStatement</span> <span class=\"geq\">:</span> <span class=\"nt\">LabelIdentifier</span> <span class=\"t\">:</span> <span class=\"nt\">LabelledItem</span></pre>\n      <emu-alg><ol><li>Return ? LabelledEvaluation of this <emu-nt>LabelledStatement</emu-nt> with argument « ».</li></ol></emu-alg>\n    ","13.4":"<dl class=\"header\">\n      </dl>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">BreakableStatement</span> <span class=\"geq\">:</span> <span class=\"nt\">IterationStatement</span></pre>\n      <emu-alg><ol><li>Let <var>stmtResult</var> be Completion(LoopEvaluation of <emu-nt>IterationStatement</emu-nt> with argument <var>labelSet</var>).</li><li>If <var>stmtResult</var> is a break completion, then<ol><li>If <var>stmtResult</var>.[[Target]] is <emu-const>empty</emu-const>, then<ol><li>If <var>stmtResult</var>.[[Value]] is <emu-const>empty</emu-const>, set <var>stmtResult</var> to NormalCompletion(<b>undefined</b>).</li><li>Else, set <var>stmtResult</var> to NormalCompletion(<var>stmtResult</var>.[[Value]]).</li></ol></li></ol></li><li>Return ? <var>stmtResult</var>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">BreakableStatement</span> <span class=\"geq\">:</span> <span class=\"nt\">SwitchStatement</span></pre>\n      <emu-alg><ol><li>Let <var>stmtResult</var> be Completion(Evaluation of <emu-nt>SwitchStatement</emu-nt>).</li><li>If <var>stmtResult</var> is a break completion, then<ol><li>If <var>stmtResult</var>.[[Target]] is <emu-const>empty</emu-const>, then<ol><li>If <var>stmtResult</var>.[[Value]] is <emu-const>empty</emu-const>, set <var>stmtResult</var> to NormalCompletion(<b>undefined</b>).</li><li>Else, set <var>stmtResult</var> to NormalCompletion(<var>stmtResult</var>.[[Value]]).</li></ol></li></ol></li><li>Return ? <var>stmtResult</var>.</li></ol></emu-alg>\n      <emu-note>\n        <p>A <emu-nt>BreakableStatement</emu-nt> is one that can be exited via an unlabelled <emu-nt>BreakStatement</emu-nt>.</p>\n      </emu-note>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">LabelledStatement</span> <span class=\"geq\">:</span> <span class=\"nt\">LabelIdentifier</span> <span class=\"t\">:</span> <span class=\"nt\">LabelledItem</span></pre>\n      <emu-alg><ol><li>Let <var>label</var> be the StringValue of <emu-nt>LabelIdentifier</emu-nt>.</li><li>Let <var>newLabelSet</var> be the list-concatenation of <var>labelSet</var> and « <var>label</var> ».</li><li>Let <var>stmtResult</var> be Completion(LabelledEvaluation of <emu-nt>LabelledItem</emu-nt> with argument <var>newLabelSet</var>).</li><li>If <var>stmtResult</var> is a break completion and <var>stmtResult</var>.[[Target]] is <var>label</var>, then<ol><li>Set <var>stmtResult</var> to NormalCompletion(<var>stmtResult</var>.[[Value]]).</li></ol></li><li>Return ? <var>stmtResult</var>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">LabelledItem</span> <span class=\"geq\">:</span> <span class=\"nt\">FunctionDeclaration</span></pre>\n      <emu-alg><ol><li>Return ? Evaluation of <emu-nt>FunctionDeclaration</emu-nt>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">Statement</span> <span class=\"geq\">:</span>\n  <span class=\"nt\">BlockStatement</span>\n  <span class=\"nt\">VariableStatement</span>\n  <span class=\"nt\">EmptyStatement</span>\n  <span class=\"nt\">ExpressionStatement</span>\n  <span class=\"nt\">IfStatement</span>\n  <span class=\"nt\">ContinueStatement</span>\n  <span class=\"nt\">BreakStatement</span>\n  <span class=\"nt\">ReturnStatement</span>\n  <span class=\"nt\">WithStatement</span>\n  <span class=\"nt\">ThrowStatement</span>\n  <span class=\"nt\">TryStatement</span>\n  <span class=\"nt\">DebuggerStatement</span></pre>\n      <emu-alg><ol><li>Return ? Evaluation of <emu-nt>Statement</emu-nt>.</li></ol></emu-alg>\n      <emu-note>\n        <p>The only two productions of <emu-nt>Statement</emu-nt> which have special semantics for LabelledEvaluation are <emu-nt>BreakableStatement</emu-nt> and <emu-nt>LabelledStatement</emu-nt>.</p>\n      </emu-note>\n    ","14.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">ThrowStatement</span> <span class=\"geq\">:</span> <span class=\"t\">throw</span> <span class=\"nt\">Expression</span> <span class=\"t\">;</span></pre>\n      <emu-alg><ol><li>Let <var>exprRef</var> be ? Evaluation of <emu-nt>Expression</emu-nt>.</li><li>Let <var>exprValue</var> be ? GetValue(<var>exprRef</var>).</li><li>Throw <var>exprValue</var>.</li></ol></emu-alg>\n    ","15.1":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">Catch</span> <span class=\"geq\">:</span> <span class=\"t\">catch</span> <span class=\"t\">(</span> <span class=\"nt\">CatchParameter</span> <span class=\"t\">)</span> <span class=\"nt\">Block</span></pre>\n      <ul>\n        <li>\n          It is a Syntax Error if the BoundNames of <emu-nt>CatchParameter</emu-nt> contains any duplicate elements.\n        </li>\n        <li>\n          It is a Syntax Error if any element of the BoundNames of <emu-nt>CatchParameter</emu-nt> also occurs in the LexicallyDeclaredNames of <emu-nt>Block</emu-nt>.\n        </li>\n        <li>\n          It is a Syntax Error if any element of the BoundNames of <emu-nt>CatchParameter</emu-nt> also occurs in the VarDeclaredNames of <emu-nt>Block</emu-nt><span normative-optional>, unless <emu-nt>CatchParameter</emu-nt> is <code class=\"emu-grammar\"><span class=\"nt lhs\">CatchParameter</span> <span class=\"geq\">:</span> <span class=\"nt\">BindingIdentifier</span></code> and the host is a web browser or otherwise supports <a href=\"/additional-ecmascript-features-for-web-browsers#sec-variablestatements-in-catch-blocks\">B.3.4</a></span>.\n        </li>\n      </ul>\n    ","15.2":"<dl class=\"header\">\n      </dl>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">Catch</span> <span class=\"geq\">:</span> <span class=\"t\">catch</span> <span class=\"t\">(</span> <span class=\"nt\">CatchParameter</span> <span class=\"t\">)</span> <span class=\"nt\">Block</span></pre>\n      <emu-alg><ol><li>Let <var>oldEnv</var> be the running execution context's LexicalEnvironment.</li><li>Let <var>catchEnv</var> be NewDeclarativeEnvironment(<var>oldEnv</var>).</li><li>For each element <var>argName</var> of the BoundNames of <emu-nt>CatchParameter</emu-nt>, do<ol><li>Perform ! <var>catchEnv</var>.CreateMutableBinding(<var>argName</var>, <b>false</b>).</li></ol></li><li>Set the running execution context's LexicalEnvironment to <var>catchEnv</var>.</li><li>Let <var>status</var> be Completion(BindingInitialization of <emu-nt>CatchParameter</emu-nt> with arguments <var>thrownValue</var> and <var>catchEnv</var>).</li><li>If <var>status</var> is an abrupt completion, then<ol><li>Set the running execution context's LexicalEnvironment to <var>oldEnv</var>.</li><li>Return ? <var>status</var>.</li></ol></li><li>Let <var>blockCompletion</var> be Completion(Evaluation of <emu-nt>Block</emu-nt>).</li><li>Set the running execution context's LexicalEnvironment to <var>oldEnv</var>.</li><li>Return ? <var>blockCompletion</var>.</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">Catch</span> <span class=\"geq\">:</span> <span class=\"t\">catch</span> <span class=\"nt\">Block</span></pre>\n      <emu-alg><ol><li>Return ? Evaluation of <emu-nt>Block</emu-nt>.</li></ol></emu-alg>\n      <emu-note>\n        <p>No matter how control leaves the <emu-nt>Block</emu-nt> the LexicalEnvironment is always restored to its former state.</p>\n      </emu-note>\n    ","15.3":"<pre class=\"emu-grammar\"><span class=\"nt lhs\">TryStatement</span> <span class=\"geq\">:</span> <span class=\"t\">try</span> <span class=\"nt\">Block</span> <span class=\"nt\">Catch</span></pre>\n      <emu-alg><ol><li>Let <var>blockResult</var> be Completion(Evaluation of <emu-nt>Block</emu-nt>).</li><li>If <var>blockResult</var> is a throw completion, let <var>catchResult</var> be Completion(CatchClauseEvaluation of <emu-nt>Catch</emu-nt> with argument <var>blockResult</var>.[[Value]]).</li><li>Else, let <var>catchResult</var> be <var>blockResult</var>.</li><li>Return ? UpdateEmpty(<var>catchResult</var>, <b>undefined</b>).</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">TryStatement</span> <span class=\"geq\">:</span> <span class=\"t\">try</span> <span class=\"nt\">Block</span> <span class=\"nt\">Finally</span></pre>\n      <emu-alg><ol><li>Let <var>blockResult</var> be Completion(Evaluation of <emu-nt>Block</emu-nt>).</li><li>Let <var>finallyResult</var> be Completion(Evaluation of <emu-nt>Finally</emu-nt>).</li><li>If <var>finallyResult</var> is a normal completion, set <var>finallyResult</var> to <var>blockResult</var>.</li><li>Return ? UpdateEmpty(<var>finallyResult</var>, <b>undefined</b>).</li></ol></emu-alg>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">TryStatement</span> <span class=\"geq\">:</span> <span class=\"t\">try</span> <span class=\"nt\">Block</span> <span class=\"nt\">Catch</span> <span class=\"nt\">Finally</span></pre>\n      <emu-alg><ol><li>Let <var>blockResult</var> be Completion(Evaluation of <emu-nt>Block</emu-nt>).</li><li>If <var>blockResult</var> is a throw completion, let <var>catchResult</var> be Completion(CatchClauseEvaluation of <emu-nt>Catch</emu-nt> with argument <var>blockResult</var>.[[Value]]).</li><li>Else, let <var>catchResult</var> be <var>blockResult</var>.</li><li>Let <var>finallyResult</var> be Completion(Evaluation of <emu-nt>Finally</emu-nt>).</li><li>If <var>finallyResult</var> is a normal completion, set <var>finallyResult</var> to <var>catchResult</var>.</li><li>Return ? UpdateEmpty(<var>finallyResult</var>, <b>undefined</b>).</li></ol></emu-alg>\n    ","16.1":"<emu-note>\n        <p>Evaluating a <emu-nt>DebuggerStatement</emu-nt> may allow an implementation to cause a breakpoint when run under a debugger. If a debugger is not present or active this statement has no observable effect.</p>\n      </emu-note>\n      <pre class=\"emu-grammar\"><span class=\"nt lhs\">DebuggerStatement</span> <span class=\"geq\">:</span> <span class=\"t\">debugger</span> <span class=\"t\">;</span></pre>\n      <emu-alg><ol><li>If an implementation-defined debugging facility is available and enabled, then<ol><li>Perform an implementation-defined debugging action.</li><li>Return a new implementation-defined Completion Record.</li></ol></li><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n    "};
const _basePath = process.env.NEXT_PUBLIC_BASE_PATH || '';
const sections = _basePath
  ? Object.fromEntries(
      Object.entries(_sections).map(([k, v]) => [
        k,
        v.replaceAll('href="/', `href="${_basePath}/`),
      ])
    )
  : _sections;
export function Sec({ id }) {
  const html = sections[id] ?? '';
  return <div className="ecma-spec" dangerouslySetInnerHTML={{ __html: html }} />;
}
